  let app: Awaited<ReturnType<typeof buildGatewayApp>>;
  const publicApiPrefixes = ['/api/hello', '/api/health/readiness', '/api/ingress/telegram', '/api/telegram/webhook'];

  const inject = async (options: Parameters<typeof app.inject>[0]): Promise<Awaited<ReturnType<typeof app.inject>>> => {
    if (typeof options === 'string') {
      return app.inject(options);
    }

    const method = String(options.method ?? 'GET').toUpperCase();
    const url = String(options.url ?? '');
    const headers = { ...(options.headers ?? {}) } as Record<string, string>;
    const skipDefaultAuth = headers['x-test-no-default-auth'] === '1';
    const hasAuth = Boolean(headers.Authorization || headers.authorization || headers['x-api-token']);
    const isApiRoute = url.startsWith('/api/');
    const isPublicApiRoute = publicApiPrefixes.some(
      (prefix) => url === prefix || url.startsWith(`${prefix}?`) || url.startsWith(`${prefix}/`)
    );

    if (isApiRoute && !isPublicApiRoute && (method === 'GET' || method === 'HEAD') && !skipDefaultAuth && !hasAuth) {
      headers.Authorization = `Bearer ${config.server.apiToken}`;
    }
    if (isApiRoute && !isPublicApiRoute && hasAuth && !headers['x-ops-role']) {
      headers['x-ops-role'] = 'operator';
    }

    return app.inject({
      ...options,
      headers
    });
  };

  const waitForTerminalRun = async (
    runId: string,
    timeoutMs = 10_000
  ): Promise<{
    runtime: string;
    effectiveRuntime: string | null;
    model: string | null;
    effectiveModel: string | null;
    status: string;
    error: string | null;
  }> => {
    const terminalStatuses = new Set(['completed', 'failed', 'aborted']);
    const deadline = Date.now() + timeoutMs;

    while (Date.now() < deadline) {
      const response = await inject({
        method: 'GET',
        url: `/api/runs/${runId}`
      });
      expect(response.statusCode).toBe(200);
      const body = response.json() as {
        run: {
          runtime: string;
          effectiveRuntime?: string | null;
          model?: string | null;
          effectiveModel?: string | null;
          status: string;
          error: string | null;
        };
      };
      if (terminalStatuses.has(body.run.status)) {
        return {
          runtime: body.run.runtime,
          effectiveRuntime: body.run.effectiveRuntime ?? null,
          model: body.run.model ?? null,
          effectiveModel: body.run.effectiveModel ?? null,
          status: body.run.status,
          error: body.run.error
        };
      }
      await new Promise((resolve) => setTimeout(resolve, 100));
    }

    throw new Error(`Run ${runId} did not reach terminal status within ${timeoutMs}ms`);
  };

  const waitForRunStatus = async (
    runId: string,
    expectedStatus: 'completed' | 'failed' | 'aborted',
    timeoutMs = 10_000
  ): Promise<{
    runtime: string;
    effectiveRuntime: string | null;
    model: string | null;
    effectiveModel: string | null;
    status: string;
    error: string | null;
  }> => {
    const deadline = Date.now() + timeoutMs;

    while (Date.now() < deadline) {
      const response = await inject({
        method: 'GET',
        url: `/api/runs/${runId}`
      });
      expect(response.statusCode).toBe(200);
      const body = response.json() as {
        run: {
          runtime: string;
          effectiveRuntime?: string | null;
          model?: string | null;
          effectiveModel?: string | null;
          status: string;
          error: string | null;
        };
      };
      if (body.run.status === expectedStatus) {
        return {
          runtime: body.run.runtime,
          effectiveRuntime: body.run.effectiveRuntime ?? null,
          model: body.run.model ?? null,
          effectiveModel: body.run.effectiveModel ?? null,
          status: body.run.status,
          error: body.run.error
        };
      }
      await new Promise((resolve) => setTimeout(resolve, 100));
    }

    throw new Error(`Run ${runId} did not reach expected status ${expectedStatus} within ${timeoutMs}ms`);
  };

  const waitForCollectionLength = async <T>(
    collection: T[],
    expectedLength: number,
    timeoutMs = 10_000
  ): Promise<void> => {
    const deadline = Date.now() + timeoutMs;
    while (Date.now() < deadline) {
      if (collection.length >= expectedLength) {
        return;
      }
      await new Promise((resolve) => setTimeout(resolve, 50));
    }
    throw new Error(`Collection did not reach length ${expectedLength} within ${timeoutMs}ms (saw ${collection.length})`);
  };

  const waitForOutboundMessageByRun = async (
    sessionId: string,
    runId: string,
    timeoutMs = 10_000
  ): Promise<{ direction: string; content: string; metadataJson: string }> => {
    const deadline = Date.now() + timeoutMs;
    while (Date.now() < deadline) {
      const response = await inject({
        method: 'GET',
        url: `/api/messages?sessionId=${encodeURIComponent(sessionId)}`
      });
      expect(response.statusCode).toBe(200);
      const body = response.json() as {
        messages: Array<{ direction: string; content: string; metadataJson: string }>;
      };
      const message = body.messages
        .filter((entry) => entry.direction === 'outbound')
        .find((entry) => {
          const metadata = JSON.parse(entry.metadataJson) as { runId?: string };
          return metadata.runId === runId;
        });
      if (message) {
        return message;
      }
      await new Promise((resolve) => setTimeout(resolve, 100));
    }
    throw new Error(`Outbound message for run ${runId} not found within ${timeoutMs}ms`);
  };

