  const waitForQueueToClearRun = async (
    runId: string,
    timeoutMs = 10_000
  ): Promise<{
    processing: Array<{ runId: string }>;
    deadLetter: Array<{ runId: string }>;
  }> => {
    const deadline = Date.now() + timeoutMs;
    while (Date.now() < deadline) {
      const response = await inject({
        method: 'GET',
        url: '/api/queue'
      });
      expect(response.statusCode).toBe(200);
      const body = response.json() as {
        processing: Array<{ runId: string }>;
        deadLetter: Array<{ runId: string }>;
      };
      const stillProcessing = body.processing.some((entry) => entry.runId === runId);
      const inDeadLetter = body.deadLetter.some((entry) => entry.runId === runId);
      if (!stillProcessing && !inDeadLetter) {
        return body;
      }
      await new Promise((resolve) => setTimeout(resolve, 100));
    }
    throw new Error(`Queue state for run ${runId} did not settle within ${timeoutMs}ms`);
  };

