  it('uses deterministic model delegation mode for CEO routing', async () => {
    const current = await inject({
      method: 'GET',
      url: '/api/config/runtime',
      headers: {
        Authorization: `Bearer ${config.server.apiToken}`
      }
    });
    expect(current.statusCode).toBe(200);
    const currentBody = current.json() as { config: Record<string, unknown> };
    const next = structuredClone(currentBody.config) as Record<string, unknown>;
    const policy = (next.policy as Record<string, unknown>) ?? {};
    policy.autoDelegation = {
      mode: 'model',
      minConfidence: 0.55,
      timeoutMs: 2500,
      maxTargets: 3
    };
    next.policy = policy;
    const runtime = (next.runtime as Record<string, unknown>) ?? {};
    const adapters = (runtime.adapters as Record<string, unknown>) ?? {};
    const ensureAdapterCommand = (name: string) => {
      const adapter = (adapters[name] as Record<string, unknown> | undefined) ?? {};
      if (typeof adapter.command !== 'string' || adapter.command.trim().length === 0) {
        adapter.command = 'node';
      }
      if (!Array.isArray(adapter.args)) {
        adapter.args = [];
      }
      adapters[name] = adapter;
    };
    ensureAdapterCommand('codex');
    ensureAdapterCommand('claude');
    ensureAdapterCommand('gemini');
    runtime.adapters = adapters;
    next.runtime = runtime;

    const updateConfig = await inject({
      method: 'PUT',
      url: '/api/config/runtime',
      headers: {
        Authorization: `Bearer ${config.server.apiToken}`
      },
      payload: {
        config: next,
        actor: 'test'
      }
    });
    expect(updateConfig.statusCode).toBe(200);

    const sourceSessionResponse = await inject({
      method: 'POST',
      url: '/api/sessions',
      headers: {
        Authorization: `Bearer ${config.server.apiToken}`
      },
      payload: {
        label: 'ceo-model-delegate',
        agentId: 'ceo-default'
      }
    });
    expect(sourceSessionResponse.statusCode).toBe(201);
    const sourceSessionBody = sourceSessionResponse.json() as { session: { id: string } };

    const runResponse = await inject({
      method: 'POST',
      url: `/api/sessions/${sourceSessionBody.session.id}/runs`,
      headers: {
        Authorization: `Bearer ${config.server.apiToken}`,
        'Idempotency-Key': 'ceo-model-delegate-run'
      },
      payload: {
        prompt: 'Build the feature and validate with QA checks before release.'
      }
    });
    expect(runResponse.statusCode).toBe(201);
    const runBody = runResponse.json() as {
      delegations: Array<{ targetAgentId: string }>;
      delegationDecision: {
        action: string;
        reason: string;
        confidence: number | null;
      } | null;
    };
    expect(runBody.delegationDecision).toBeTruthy();
    expect([
      'answer_direct',
      'delegate',
      'direct_execute',
      'plan_backlog',
      'fail_missing_capability',
      'no_match',
      'ask_clarify'
    ]).toContain(runBody.delegationDecision?.action);
    if (runBody.delegationDecision?.action === 'delegate') {
      expect(runBody.delegations.length).toBeGreaterThanOrEqual(1);
    }
  });

