  it('falls back CEO delegation routing to OpenRouter when Gemini returns provider saturation', async () => {
    const originalFetch = globalThis.fetch;
    const previousOpenRouterApiKey = process.env.OPENROUTER_API_KEY;
    const previousGoogleApiKey = process.env.GOOGLE_API_KEY;
    process.env.OPENROUTER_API_KEY = 'openrouter-test-key-for-routing';
    process.env.GOOGLE_API_KEY = 'google-test-key-for-routing';

    const fetchMock = vi.fn(async (input: URL | RequestInfo) => {
      const url = typeof input === 'string' ? input : input instanceof URL ? input.toString() : input.url;
      if (url.includes('generativelanguage.googleapis.com')) {
        return new Response(
          JSON.stringify({
            error: {
              message: '503 service unavailable: model temporarily overloaded'
            }
          }),
          {
            status: 503,
            headers: {
              'content-type': 'application/json'
            }
          }
        );
      }
      if (url.includes('openrouter.ai/api/v1/chat/completions')) {
        return new Response(
          JSON.stringify({
            choices: [
              {
                message: {
                  content:
                    '{"action":"direct","targetAgentIds":[],"confidence":0.93,"reason":"fallback route answered routing decision"}'
                }
              }
            ],
            usage: {
              prompt_tokens: 88,
              completion_tokens: 17,
              total_tokens: 105
            }
          }),
          {
            status: 200,
            headers: {
              'content-type': 'application/json'
            }
          }
        );
      }
      throw new Error(`Unexpected fetch url: ${url}`);
    });
    vi.stubGlobal('fetch', fetchMock);

    const setDispatchMode = await inject({
      method: 'PATCH',
      url: '/api/agents/profiles/ceo-default',
      headers: {
        Authorization: `Bearer ${config.server.apiToken}`
      },
      payload: {
        executionMode: 'dispatch_only'
      }
    });
    expect(setDispatchMode.statusCode).toBe(200);

    const limitsUpdate = await inject({
      method: 'PUT',
      url: '/api/llm/limits',
      headers: {
        Authorization: `Bearer ${config.server.apiToken}`
      },
      payload: {
        limits: {
          orchestratorPrimaryModelByRuntime: {
            process: 'gemini-3.1-pro-preview'
          },
          orchestratorFallbackByRuntime: {
            process: [{ runtime: 'process', model: 'openrouter/openai/gpt-5-mini' }]
          }
        }
      }
    });
    expect(limitsUpdate.statusCode).toBe(200);

    try {
      const sourceSessionResponse = await inject({
        method: 'POST',
        url: '/api/sessions',
        headers: {
          Authorization: `Bearer ${config.server.apiToken}`
        },
        payload: {
          label: 'ceo-router-provider-saturation-fallback',
          agentId: 'ceo-default'
        }
      });
      expect(sourceSessionResponse.statusCode).toBe(201);
      const sourceSessionBody = sourceSessionResponse.json() as { session: { id: string } };

      const runResponse = await inject({
        method: 'POST',
        url: `/api/sessions/${sourceSessionBody.session.id}/runs`,
        headers: {
          Authorization: `Bearer ${config.server.apiToken}`,
          'Idempotency-Key': 'ceo-router-provider-saturation-fallback'
        },
        payload: {
          prompt: 'Decide whether to delegate this quick hello',
          runtime: 'process'
        }
      });
      expect(runResponse.statusCode).toBe(201);

      const costs = await inject({
        method: 'GET',
        url: '/api/llm/costs'
      });
      expect(costs.statusCode).toBe(200);
      const costsBody = costs.json() as {
        costs: {
          recentEvents: Array<{
            sessionId: string | null;
            provider: string;
            taskType: string;
            status: string;
          }>;
        };
      };
      const routerEvents = costsBody.costs.recentEvents.filter(
        (event) => event.sessionId === sourceSessionBody.session.id && event.taskType === 'router'
      );
      expect(routerEvents.some((event) => event.provider === 'google' && event.status === 'failed')).toBe(true);
      expect(routerEvents.some((event) => event.provider === 'openrouter' && event.status === 'completed')).toBe(true);
    } finally {
      await inject({
        method: 'PATCH',
        url: '/api/agents/profiles/ceo-default',
        headers: {
          Authorization: `Bearer ${config.server.apiToken}`
        },
        payload: {
          executionMode: 'on_demand'
        }
      });
      await inject({
        method: 'PUT',
        url: '/api/llm/limits',
        headers: {
          Authorization: `Bearer ${config.server.apiToken}`
        },
        payload: {
          limits: {}
        }
      });
      vi.stubGlobal('fetch', originalFetch);
      if (previousOpenRouterApiKey === undefined) {
        delete process.env.OPENROUTER_API_KEY;
      } else {
        process.env.OPENROUTER_API_KEY = previousOpenRouterApiKey;
      }
      if (previousGoogleApiKey === undefined) {
        delete process.env.GOOGLE_API_KEY;
      } else {
        process.env.GOOGLE_API_KEY = previousGoogleApiKey;
      }
    }
  });

  it('links Telegram direct chat to a dashboard session via one-time code', async () => {
    const createSession = await inject({
      method: 'POST',
      url: '/api/sessions',
      headers: {
        Authorization: `Bearer ${config.server.apiToken}`
      },
      payload: {
        label: 'link-target',
        runtime: 'process'
      }
    });
    expect(createSession.statusCode).toBe(201);
    const sessionBody = createSession.json() as { session: { id: string; sessionKey: string } };

    const issueLink = await inject({
      method: 'POST',
      url: `/api/sessions/${sessionBody.session.id}/link-code`,
      headers: {
        Authorization: `Bearer ${config.server.apiToken}`
      },
      payload: {
        ttlSec: 600
      }
    });
    expect(issueLink.statusCode).toBe(201);
    const linkBody = issueLink.json() as { link: { code: string; command: string } };
    expect(linkBody.link.code.length).toBeGreaterThan(0);
    expect(linkBody.link.command.startsWith('/link ')).toBe(true);

    const linkIngress = await inject({
      method: 'POST',
      url: '/api/ingress/telegram',
      payload: {
        update_id: 300,
        message: {
          text: linkBody.link.command,
          chat: { id: 901, type: 'private' },
          from: { id: 555, username: 'linker' },
          mentioned: true
        }
      }
    });
    expect(linkIngress.statusCode).toBe(200);
    const linkIngressBody = linkIngress.json() as { status: string; command: string; sessionId: string };
    expect(linkIngressBody.status).toBe('command_applied');
    expect(linkIngressBody.command).toBe('link');
    expect(linkIngressBody.sessionId).toBe(sessionBody.session.id);

    const postLinkMessage = await inject({
      method: 'POST',
      url: '/api/ingress/telegram',
      payload: {
        update_id: 301,
        message: {
          text: 'run after link',
          chat: { id: 901, type: 'private' },
          from: { id: 555, username: 'linker' },
          mentioned: true
        }
      }
    });
    expect(postLinkMessage.statusCode).toBe(200);
    const postLinkBody = postLinkMessage.json() as { status: string; sessionId: string; runId: string };
    expect(postLinkBody.status).toBe('queued');
    expect(postLinkBody.sessionId).toBe(sessionBody.session.id);
    expect(postLinkBody.runId).toBeTruthy();

    const replayLink = await inject({
      method: 'POST',
      url: '/api/ingress/telegram',
      payload: {
        update_id: 302,
        message: {
          text: linkBody.link.command,
          chat: { id: 901, type: 'private' },
          from: { id: 555, username: 'linker' },
          mentioned: true
        }
      }
    });
    expect(replayLink.statusCode).toBe(200);
    const replayBody = replayLink.json() as { status: string; reason: string };
    expect(replayBody.status).toBe('blocked');
    expect(replayBody.reason).toBe('invalid_or_expired_link_code');
  });

  it('supports Telegram /resume for waiting_input runs', async () => {
    const senderId = 7654321;
    const boot = await inject({
      method: 'POST',
      url: '/api/ingress/telegram',
      payload: {
        update_id: 31001,
        message: {
          text: 'start resume scenario',
          chat: { id: senderId, type: 'private' },
          from: { id: senderId, username: 'resumer' },
          mentioned: true
        }
      }
    });
    expect(boot.statusCode).toBe(200);
    const bootBody = boot.json() as { sessionId: string; runId: string };
    expect(bootBody.sessionId).toBeTruthy();
    expect(bootBody.runId).toBeTruthy();
    await waitForTerminalRun(bootBody.runId, 20_000);

    const waitingRun = await inject({
      method: 'POST',
      url: `/api/sessions/${bootBody.sessionId}/runs`,
      headers: {
        Authorization: `Bearer ${config.server.apiToken}`,
        'Idempotency-Key': 'telegram-resume-waiting-run'
      },
      payload: {
        prompt: 'seed waiting run for telegram resume',
        runtime: 'process'
      }
    });
    expect(waitingRun.statusCode).toBe(201);
    const waitingRunBody = waitingRun.json() as { run: { id: string } };
    await waitForTerminalRun(waitingRunBody.run.id, 20_000);

    const db = new ControlPlaneDatabase(path.join(root, 'state.db'));
    db.updateRunStatus({
      runId: waitingRunBody.run.id,
      status: 'waiting_input',
      resultSummary: 'manual waiting_input for telegram /resume',
      error: null
    });

    const resume = await inject({
      method: 'POST',
      url: '/api/ingress/telegram',
      payload: {
        update_id: 31002,
        message: {
          text: '/resume continue after credentials fix',
          chat: { id: senderId, type: 'private' },
          from: { id: senderId, username: 'resumer' },
          mentioned: true
        }
      }
    });
    expect(resume.statusCode).toBe(200);
    const resumeBody = resume.json() as {
      status: string;
      command: string;
      runId: string;
      runStatus: string;
      heartbeat: string;
    };
    expect(resumeBody.status).toBe('command_applied');
    expect(resumeBody.command).toBe('resume');
    expect(resumeBody.runId).toBe(waitingRunBody.run.id);
    expect(['completed', 'waiting_input', 'failed']).toContain(resumeBody.runStatus);
    expect(['running', 'waiting_input', 'completed', 'failed', 'unknown']).toContain(resumeBody.heartbeat);
  }, 40_000);

  it('manages runtime config through authenticated API', async () => {
    const unauthorized = await inject({
      method: 'GET',
      url: '/api/config/runtime',
      headers: {
        'x-test-no-default-auth': '1'
      }
    });
    expect(unauthorized.statusCode).toBe(401);

    const unauthorizedWrite = await inject({
      method: 'PUT',
      url: '/api/config/runtime',
      payload: { config }
    });
    expect(unauthorizedWrite.statusCode).toBe(401);

    const current = await inject({
      method: 'GET',
      url: '/api/config/runtime',
      headers: {
        Authorization: `Bearer ${config.server.apiToken}`
      }
    });
    expect(current.statusCode).toBe(200);
    const currentBody = current.json() as {
      config: Record<string, unknown>;
      sensitive: Record<
        string,
        {
          configured: boolean;
          source: 'unset' | 'plain' | 'env' | 'vault';
          redacted: boolean;
        }
      >;
      configMeta: { runtimeConfigPath: string | null; writable: boolean };
    };
    expect(currentBody.configMeta.writable).toBe(true);
    expect(currentBody.configMeta.runtimeConfigPath).toBe(runtimeConfigPath);
    expect((currentBody.config.server as Record<string, unknown>).apiToken).toBe('__REDACTED__');
    expect((currentBody.config.channel as Record<string, unknown>).telegram).toBeDefined();
    const telegramConfig = (currentBody.config.channel as Record<string, unknown>).telegram as Record<string, unknown>;
    expect(telegramConfig.botToken).toBe('__REDACTED__');
    expect(currentBody.sensitive['server.apiToken']).toMatchObject({
      configured: true,
      source: 'plain',
      redacted: true
    });

    const next = structuredClone(currentBody.config) as Record<string, unknown>;
    const server = (next.server as Record<string, unknown>) ?? {};
    server.port = 8788;
    next.server = server;
    const queue = (next.queue as Record<string, unknown>) ?? {};
    const retry = (queue.retry as Record<string, unknown>) ?? {};
    retry.baseDelayMs = 100;
    queue.retry = retry;
    next.queue = queue;
    const runtime = (next.runtime as Record<string, unknown>) ?? {};
    const adapters = (runtime.adapters as Record<string, Record<string, unknown>>) ?? {};
    adapters.codex = { ...(adapters.codex ?? {}), command: 'codex' };
    adapters.claude = { ...(adapters.claude ?? {}), command: 'claude' };
    adapters.gemini = { ...(adapters.gemini ?? {}), command: 'gemini' };
    adapters.process = { ...(adapters.process ?? {}), command: 'node' };
    runtime.adapters = adapters;
    next.runtime = runtime;
    const memory = (next.memory as Record<string, unknown>) ?? {};
    const embedding = (memory.embedding as Record<string, unknown>) ?? {};
    embedding.provider = 'noop';
    embedding.voyageApiKey = 'inline-voyage-key';
    memory.embedding = embedding;
    next.memory = memory;

    const updated = await inject({
      method: 'PUT',
      url: '/api/config/runtime',
      headers: {
        Authorization: `Bearer ${config.server.apiToken}`
      },
      payload: {
        config: next,
        actor: 'test'
      }
    });
    expect(updated.statusCode).toBe(200);
    const updatedBody = updated.json() as {
      saved: boolean;
      restartRequired: boolean;
      config: Record<string, unknown>;
    };
    expect(updatedBody.saved).toBe(true);
    expect(updatedBody.restartRequired).toBe(true);
    expect((updatedBody.config.server as Record<string, unknown>).apiToken).toBe('__REDACTED__');

    const db = new ControlPlaneDatabase(path.join(root, 'state.db'));
    try {
      const overlay = db.getRuntimeConfigOverlay();
      expect(overlay).toBeTruthy();
      const persisted = JSON.parse(overlay?.configJson ?? '{}') as {
        memory: { embedding: { provider: string } };
        server: { apiToken: string };
        channel: { telegram: { botToken: string } };
      };
      expect(persisted.memory.embedding.provider).toBe('voyage');
      expect(persisted.server.apiToken).toBe(config.server.apiToken);
      expect(persisted.channel.telegram.botToken).toBe(config.channel.telegram.botToken);
    } finally {
      db.close();
    }
  });

  it('skips sqlite runtime config overlay when booted from an explicit non-default config path', async () => {
    const customRoot = fs.mkdtempSync(path.join(os.tmpdir(), 'ops-config-overlay-skip-'));
    const customConfig = structuredClone(config) as any;
    customConfig.server.port = 8798;
    customConfig.runtime.workspaceRoot = path.join(customRoot, 'isolated-workspaces');
    customConfig.persistence.sqlitePath = path.join(customRoot, 'state.db');
    fs.mkdirSync(customConfig.runtime.workspaceRoot, { recursive: true });

    const db = new ControlPlaneDatabase(customConfig.persistence.sqlitePath);
    try {
      db.migrate();
      db.upsertAgentProfile({
        id: 'ceo-default',
        name: 'CEO',
        title: 'Chief Executive Officer',
        systemPrompt: 'Coordinate repository work.',
        defaultRuntime: 'process',
        allowedRuntimes: ['process', 'codex', 'claude', 'gemini'],
        tools: ['runtime:process'],
        metadata: {
          executionMode: 'on_demand'
        },
        enabled: true
      });

      const overlaidConfig = structuredClone(customConfig) as any;
      overlaidConfig.server.port = 8788;
      overlaidConfig.runtime.workspaceRoot = path.join(customRoot, 'overlay-workspaces');
      db.upsertRuntimeConfigOverlay(overlaidConfig as Record<string, unknown>);
    } finally {
      db.close();
    }

    const explicitConfigPath = path.join(customRoot, 'isolated-config.json');
    fs.writeFileSync(explicitConfigPath, `${JSON.stringify(customConfig, null, 2)}\n`, 'utf8');

    const customApp = await buildGatewayApp(customConfig, {
      runtimeConfigPath: explicitConfigPath,
      skillInstallRunner
    });
    const customInject = (options: Parameters<typeof customApp.inject>[0]) =>
      customApp.inject(
        typeof options === 'string'
          ? options
          : {
              ...options,
              headers: {
                Authorization: `Bearer ${customConfig.server.apiToken}`,
                'x-ops-role': 'operator',
                ...(options.headers ?? {})
              }
            }
      );

    const waitForCustomRun = async (runId: string, timeoutMs = 10_000): Promise<void> => {
      const deadline = Date.now() + timeoutMs;
      while (Date.now() < deadline) {
        const response = await customInject({
          method: 'GET',
          url: `/api/runs/${runId}`
        });
        expect(response.statusCode).toBe(200);
        const body = response.json() as {
          run: {
            status: string;
          };
        };
        if (['completed', 'failed', 'aborted'].includes(body.run.status)) {
          return;
        }
        await new Promise((resolve) => setTimeout(resolve, 100));
      }
      throw new Error(`Run ${runId} did not reach terminal status within ${timeoutMs}ms`);
    };

    try {
      const sessionResponse = await customInject({
        method: 'POST',
        url: '/api/sessions',
        payload: {
          label: 'overlay-skip-session',
          agentId: 'ceo-default',
          runtime: 'process',
          model: 'default'
        }
      });
      expect(sessionResponse.statusCode).toBe(201);
      const sessionBody = sessionResponse.json() as {
        session: {
          id: string;
        };
      };

      const runResponse = await customInject({
        method: 'POST',
        url: `/api/sessions/${sessionBody.session.id}/runs`,
        headers: {
          'Idempotency-Key': 'overlay-skip-run'
        },
        payload: {
          prompt: 'Verify the explicit config path keeps the isolated workspace root.',
          runtime: 'process',
          autoDelegate: false
        }
      });
      expect(runResponse.statusCode).toBe(201);
      const runBody = runResponse.json() as {
        run: {
          id: string;
        };
      };
      await waitForCustomRun(runBody.run.id);

      const terminalResponse = await customInject({
        method: 'GET',
        url: `/api/runs/${runBody.run.id}/terminal`
      });
      expect(terminalResponse.statusCode).toBe(200);
      const terminalBody = terminalResponse.json() as {
        terminal: {
          workspacePath: string | null;
        } | null;
      };
      expect(terminalBody.terminal?.workspacePath).toBe(path.join(customConfig.runtime.workspaceRoot, sessionBody.session.id));
      expect(terminalBody.terminal?.workspacePath).not.toContain(path.join(customRoot, 'overlay-workspaces'));
    } finally {
      await customApp.close();
    }
  });

