    const currentBody = current.json() as { config: Record<string, unknown> };
    const baseConfig = structuredClone(currentBody.config) as Record<string, unknown>;

    const channel = ((baseConfig.channel as Record<string, unknown> | undefined) ?? {}) as Record<string, unknown>;
    const telegram = ((channel.telegram as Record<string, unknown> | undefined) ?? {}) as Record<string, unknown>;
    telegram.debugRawOutput = false;
    channel.telegram = telegram;
    baseConfig.channel = channel;

    const policy = ((baseConfig.policy as Record<string, unknown> | undefined) ?? {}) as Record<string, unknown>;
    policy.requirePairing = false;
    baseConfig.policy = policy;
    const runtime = ((baseConfig.runtime as Record<string, unknown> | undefined) ?? {}) as Record<string, unknown>;
    const adapters = ((runtime.adapters as Record<string, unknown> | undefined) ?? {}) as Record<string, unknown>;
    const ensureAdapterCommand = (name: string) => {
      const adapter = ((adapters[name] as Record<string, unknown> | undefined) ?? {}) as Record<string, unknown>;
      if (typeof adapter.command !== 'string' || adapter.command.trim().length === 0) {
        adapter.command = 'node';
      }
      if (!Array.isArray(adapter.args)) {
        adapter.args = [];
      }
      adapters[name] = adapter;
    };
