  it('suppresses stale backlog receipts when watchdog recovery creates a superseding delegated run', async () => {
    const customRoot = fs.mkdtempSync(path.join(os.tmpdir(), 'ops-watchdog-supersede-'));
    const customConfig = structuredClone(config) as any;
    customConfig.server.port = 8791;
    customConfig.runtime.workspaceRoot = path.join(customRoot, 'workspaces');
    customConfig.persistence.sqlitePath = path.join(customRoot, 'state.db');
    customConfig.runtime.adapters.codex = {
      command: 'node',
      args: [
        '-e',
        [
          'process.stdin.resume();',
          'const finish = (code, label) => { try { process.stdout.write(label); } catch {} process.exit(code); };',
          "const timer = setTimeout(() => finish(0, 'LONG_RUNNING_DONE\\n'), 30000);",
          "process.on('SIGTERM', () => { clearTimeout(timer); finish(143, 'WATCHDOG_ABORTED\\n'); });",
          "process.on('SIGINT', () => { clearTimeout(timer); finish(130, 'WATCHDOG_ABORTED\\n'); });"
        ].join(' ')
      ]
    };
    fs.mkdirSync(customConfig.runtime.workspaceRoot, { recursive: true });

    const customApp = await buildGatewayApp(customConfig, {
      skillInstallRunner
    });
    const customInject = (options: Parameters<typeof customApp.inject>[0]) =>
      customApp.inject(
        typeof options === 'string'
          ? options
          : {
              ...options,
              headers: {
                Authorization: `Bearer ${customConfig.server.apiToken}`,
                'x-ops-role': 'operator',
                ...(options.headers ?? {})
              }
            }
      );
    try {
      const customDb = new ControlPlaneDatabase(customConfig.persistence.sqlitePath);
      const deliveryAgentId = 'custom-ceo';
      const delegatedAgentId = 'custom-engineer';
      customDb.upsertAgentProfile({
        id: deliveryAgentId,
        name: 'Custom CEO',
        title: 'Chief Executive Agent',
        systemPrompt: 'Coordinate work.',
        defaultRuntime: 'process',
        allowedRuntimes: ['process', 'codex', 'claude', 'gemini'],
        tools: ['runtime:process']
      });
      customDb.upsertAgentProfile({
        id: delegatedAgentId,
        name: 'Custom Engineer',
        title: 'Software Engineer',
        parentAgentId: deliveryAgentId,
        systemPrompt: 'Implement changes.',
        defaultRuntime: 'process',
        allowedRuntimes: ['process', 'codex', 'claude', 'gemini'],
        tools: ['runtime:process']
      });
      const deliveryTargetSession = customDb.upsertSessionByKey({
        sessionKey: 'watchdog-recovery-target',
        channel: 'internal',
        chatType: 'internal',
        agentId: deliveryAgentId,
        preferredRuntime: 'process'
      });

      const delegatedSessionKey = 'watchdog-recovery-delegate';
      const delegatedSession = customDb.upsertSessionByKey({
        sessionKey: delegatedSessionKey,
        channel: 'internal',
        chatType: 'internal',
        agentId: delegatedAgentId,
        preferredRuntime: 'process',
        metadata: {
          source: 'delegate',
          mode: 'backlog_dispatch',
          deliveryTargetSessionId: deliveryTargetSession.id
        }
      });

      const delegatedRun = customDb.createRun({
        sessionId: delegatedSession.id,
        runtime: 'process',
        requestedRuntime: 'process',
        effectiveRuntime: 'process',
        triggerSource: 'agent_delegate',
        prompt: 'Run a long-lived implementation so watchdog recovery can supersede it.',
        status: 'queued'
      });

      const backlogItem = customDb.createBacklogItem({
        title: 'Watchdog recovery should not block active backlog delivery',
        description: 'Superseded delegated runs must not emit stale aborted receipts.',
        state: 'in_progress',
        priority: 82,
        source: 'execution_contract',
        sourceRef: 'test-watchdog-recovery',
        createdBy: 'test',
        assignedAgentId: delegatedAgentId,
        linkedSessionId: delegatedSession.id,
        linkedRunId: delegatedRun.id
      });
      customDb.upsertSessionByKey({
        sessionKey: delegatedSessionKey,
        channel: 'internal',
        chatType: 'internal',
        agentId: delegatedAgentId,
        preferredRuntime: 'process',
        metadata: {
          source: 'delegate',
          mode: 'backlog_dispatch',
          backlogItemId: backlogItem.id,
          deliveryTargetSessionId: deliveryTargetSession.id
        }
      });

      customDb.enqueueQueueItem({
        lane: customConfig.queue.defaultLane,
        sessionId: delegatedSession.id,
        runId: delegatedRun.id,
        payload: {
          source: 'agent_delegate',
          metadata: {
            backlogItemId: backlogItem.id,
            deliveryTargetSessionId: deliveryTargetSession.id
          }
        },
        priority: 90,
        maxAttempts: customConfig.queue.retry.maxAttempts
      });

      const runningDeadline = Date.now() + 15_000;
      while (Date.now() < runningDeadline) {
        const run = customDb.getRunById(delegatedRun.id);
        if (run?.status === 'running') {
          break;
        }
        await new Promise((resolve) => setTimeout(resolve, 100));
      }
      expect(customDb.getRunById(delegatedRun.id)?.status).toBe('running');

      const simulate = await customInject({
        method: 'POST',
        url: '/api/watchdog/simulate',
        payload: {
          runId: delegatedRun.id,
          runtime: 'process',
          status: 'quota_exceeded',
          recommendation: 'abort_and_retry',
          detectedPattern: '429',
          matchedSignature: 'codex_quota_rate_limit',
          lastOutputAgeMs: 250,
          metadata: {
            sessionId: delegatedSession.id
          }
        }
      });
      expect(simulate.statusCode).toBe(200);

      const abortedDeadline = Date.now() + 10_000;
      while (Date.now() < abortedDeadline) {
        const run = customDb.getRunById(delegatedRun.id);
        if (run?.status === 'aborted') {
          break;
        }
        await new Promise((resolve) => setTimeout(resolve, 100));
      }
      expect(customDb.getRunById(delegatedRun.id)?.status).toBe('aborted');

      const replacementRun = customDb.findLatestRunSuperseding(delegatedRun.id);
      expect(replacementRun).toBeTruthy();

      const refreshedItem = customDb.getBacklogItemById(backlogItem.id);
      expect(refreshedItem?.state).toBe('in_progress');
      expect(refreshedItem?.blockedReason).toBeNull();
      expect([delegatedRun.id, replacementRun?.id ?? null]).toContain(refreshedItem?.linkedRunId ?? null);

      const outboundMessages = customDb
        .listMessages(deliveryTargetSession.id, 50)
        .filter((entry) => entry.direction === 'outbound')
        .map((entry) => ({
          content: entry.content,
          metadata: JSON.parse(entry.metadataJson) as {
            command?: string;
            status?: string;
            delegatedRunId?: string;
          }
        }));

      expect(
        outboundMessages.some(
          (entry) =>
            entry.metadata.command === 'backlog_receipt' &&
            entry.metadata.delegatedRunId === delegatedRun.id &&
            entry.metadata.status === 'aborted'
        )
      ).toBe(false);

      const delegatedSessionOutbox = customDb
        .listMessages(delegatedSession.id, 50)
        .filter((entry) => entry.direction === 'outbound')
        .map((entry) => ({
          sender: entry.sender,
          content: entry.content,
          metadata: JSON.parse(entry.metadataJson) as {
            runId?: string;
            status?: string;
          }
        }));
      expect(
        delegatedSessionOutbox.some(
          (entry) => entry.sender === 'agent' && entry.metadata.runId === delegatedRun.id && entry.metadata.status === 'aborted'
        )
      ).toBe(false);
    } finally {
      await customApp.close();
    }
  }, 20_000);

  it('queues a delivery-truth remediation retry when delegated backlog completion returns a script/proposal or JSON command plan instead of executed work', async () => {
    const customRoot = fs.mkdtempSync(path.join(os.tmpdir(), 'ops-delivery-truth-retry-'));
    const customConfig = structuredClone(config) as any;
    customConfig.server.port = 8792;
    customConfig.runtime.workspaceRoot = path.join(customRoot, 'workspaces');
    customConfig.persistence.sqlitePath = path.join(customRoot, 'state.db');
    customConfig.runtime.adapters.process = {
      command: 'node',
      args: [
        '-e',
        [
          "const fs = require('node:fs');",
          "const marker = '.delivery-truth-first-pass';",
          "process.stdin.resume();",
          "process.stdin.on('end', () => {",
          "  if (fs.existsSync(marker)) {",
          "    fs.writeFileSync('contact-final.txt', 'contact page ready\\n');",
          "    process.stdout.write('Outcome: completed\\nChanged files: contact-final.txt\\nChecks: none\\n');",
          '    process.exit(0);',
          '  }',
          "  fs.writeFileSync(marker, '1\\n');",
          "  fs.writeFileSync('contact.txt', 'partial contact route\\n');",
          '  process.stdout.write([',
          "    'I need to gather evidence for the contact route first.',",
          "    '```json',",
          '    \'[{\\"name\\":\\"node\\",\\"arguments\\":{\\"args\\":[\\"-e\\",\\"console.log(\\\\\\"run build\\\\\\")\\"]}}]\',',
          "    '```',",
          "    'I will execute the verification once the command plan is approved.'",
          "  ].join('\\n'));",
          '  process.exit(0);',
          '});'
        ].join(' ')
      ]
    };
    fs.mkdirSync(customConfig.runtime.workspaceRoot, { recursive: true });

    const customApp = await buildGatewayApp(customConfig, {
      skillInstallRunner
    });
    const customInject = (options: Parameters<typeof customApp.inject>[0]) =>
      customApp.inject(
        typeof options === 'string'
          ? options
          : {
              ...options,
              headers: {
                Authorization: `Bearer ${customConfig.server.apiToken}`,
                'x-ops-role': 'operator',
                ...(options.headers ?? {})
              }
            }
      );
    const customWaitForTerminalRun = async (
      runId: string,
      timeoutMs = 10_000
    ): Promise<{
      runtime: string;
      effectiveRuntime: string | null;
      model: string | null;
      effectiveModel: string | null;
      status: string;
      error: string | null;
    }> => {
      const terminalStatuses = new Set(['completed', 'failed', 'aborted']);
      const deadline = Date.now() + timeoutMs;

      while (Date.now() < deadline) {
        const response = await customInject({
          method: 'GET',
          url: `/api/runs/${runId}`
        });
        expect(response.statusCode).toBe(200);
        const body = response.json() as {
          run: {
            runtime: string;
            effectiveRuntime?: string | null;
            model?: string | null;
            effectiveModel?: string | null;
            status: string;
            error: string | null;
          };
        };
        if (terminalStatuses.has(body.run.status)) {
          return {
            runtime: body.run.runtime,
            effectiveRuntime: body.run.effectiveRuntime ?? null,
            model: body.run.model ?? null,
            effectiveModel: body.run.effectiveModel ?? null,
            status: body.run.status,
            error: body.run.error
          };
        }
        await new Promise((resolve) => setTimeout(resolve, 100));
      }

      throw new Error(`Timed out waiting for run ${runId}`);
    };

    try {
      const repoRoot = path.join(customConfig.runtime.workspaceRoot, 'ugothere.ai');
      fs.mkdirSync(repoRoot, { recursive: true });
      const runGit = (args: string[]): void => {
        const result = spawnSync('git', ['-C', repoRoot, ...args], {
          encoding: 'utf8'
        });
        expect(result.status).toBe(0);
      };
      runGit(['init', '--initial-branch=main']);
      runGit(['config', 'user.name', 'Gateway Integration']);
      runGit(['config', 'user.email', 'gateway-integration@elyzelabs.local']);
      fs.writeFileSync(path.join(repoRoot, 'README.md'), '# delivery truth repo\n');
      runGit(['add', 'README.md']);
      runGit(['commit', '-m', 'init']);

      const customDb = new ControlPlaneDatabase(customConfig.persistence.sqlitePath);
      const sourceAgentId = 'custom-ceo';
      const delegatedAgentId = 'custom-engineer';
      customDb.upsertAgentProfile({
        id: sourceAgentId,
        name: 'Custom CEO',
        title: 'Chief Executive Agent',
        systemPrompt: 'Coordinate work.',
        defaultRuntime: 'process',
        allowedRuntimes: ['process', 'codex', 'claude', 'gemini'],
        tools: ['runtime:process']
      });
      customDb.upsertAgentProfile({
        id: delegatedAgentId,
        name: 'Custom Engineer',
        title: 'Software Engineer',
        parentAgentId: sourceAgentId,
        systemPrompt: 'Implement changes.',
        defaultRuntime: 'process',
        allowedRuntimes: ['process', 'codex', 'claude', 'gemini'],
        tools: ['runtime:process', 'node']
      });
      const sourceSession = customDb.upsertSessionByKey({
        sessionKey: 'delivery-truth-source',
        channel: 'internal',
        chatType: 'internal',
        agentId: sourceAgentId,
        preferredRuntime: 'process'
      });
      const backlogItem = customDb.createBacklogItem({
        title: 'Clone ugothere.ai and add a contact page',
        description: 'Require a real repo diff before review.',
        state: 'planned',
        priority: 90,
        source: 'execution_contract',
        createdBy: 'test',
        linkedSessionId: sourceSession.id,
        repoRoot
      });
      const delegatedSession = customDb.upsertSessionByKey({
        sessionKey: 'delegate:delivery-truth',
        channel: 'internal',
        chatType: 'internal',
        agentId: delegatedAgentId,
        preferredRuntime: 'process',
        metadata: {
          source: 'delegate',
          mode: 'backlog_dispatch',
          backlogItemId: backlogItem.id,
          deliveryTargetSessionId: sourceSession.id,
          runtimeOverrides: {
            cwd: repoRoot
          }
        }
      });
      const delegatedRun = customDb.createRun({
        sessionId: delegatedSession.id,
        runtime: 'process',
        requestedRuntime: 'process',
        effectiveRuntime: 'process',
        triggerSource: 'dashboard',
        prompt: 'Clone ugothere.ai and add a contact page.',
        status: 'queued'
      });
      customDb.updateBacklogItem(backlogItem.id, {
        assignedAgentId: delegatedAgentId,
        linkedSessionId: delegatedSession.id,
        linkedRunId: delegatedRun.id
      });
      customDb.transitionBacklogItem({
        itemId: backlogItem.id,
        toState: 'in_progress',
        actor: 'test',
        reason: 'Seed delegated backlog run for delivery truth validation'
      });
      customDb.enqueueQueueItem({
        lane: customConfig.queue.defaultLane,
        sessionId: delegatedSession.id,
        runId: delegatedRun.id,
        payload: {
          source: 'test',
          metadata: {
            forceRequestedRuntime: true
          }
        },
        priority: 90,
        maxAttempts: customConfig.queue.retry.maxAttempts
      });

      const backlogItemId = backlogItem.id;
      const delegatedRunId = delegatedRun.id;

      const firstRun = await customWaitForTerminalRun(delegatedRunId, 20_000);
      expect(['completed', 'failed']).toContain(firstRun.status);
      const inspectDb = new ControlPlaneDatabase(customConfig.persistence.sqlitePath);
      let failedInitialRun = inspectDb.getRunById(delegatedRunId);
      const remediationDeadline = Date.now() + 20_000;
      while (Date.now() < remediationDeadline) {
        failedInitialRun = inspectDb.getRunById(delegatedRunId);
        if (failedInitialRun?.error === 'delivery_truth_validation_retry_queued') {
          break;
        }
        await new Promise((resolve) => setTimeout(resolve, 100));
      }
      expect(failedInitialRun?.status).toBe('failed');
      expect(failedInitialRun?.error).toBe('delivery_truth_validation_retry_queued');
      expect(failedInitialRun?.resultSummary ?? '').toContain('script/proposal');
      expect(failedInitialRun?.resultSummary ?? '').toContain('remediation retry was queued automatically');

      const replacementRunRecord = inspectDb.findLatestRunSuperseding(delegatedRunId);
      expect(replacementRunRecord).toBeTruthy();
      expect(replacementRunRecord?.prompt ?? '').toContain('DELIVERY_TRUTH_RETRY:');
      expect(replacementRunRecord?.prompt ?? '').toContain('Do not return a shell script');
      expect(replacementRunRecord?.prompt ?? '').toContain('never invent email addresses');

      const replacementRun = await customWaitForTerminalRun(String(replacementRunRecord?.id), 20_000);
      expect(replacementRun.status).toBe('completed');

      let detailsBody:
        | {
            item: {
              state: string;
              linkedRunId: string | null;
              delivery: null | {
                status: string;
                metadata: {
                  latestDelegatedRun?: {
                    runId?: string;
                  };
                  artifacts?: {
                    changedFiles?: string[];
                  };
                };
              };
            };
          }
        | undefined;
      const deadline = Date.now() + 20_000;
      while (Date.now() < deadline) {
        const details = await customInject({
          method: 'GET',
          url: `/api/backlog/items/${encodeURIComponent(backlogItemId)}`
        });
        expect(details.statusCode).toBe(200);
        detailsBody = details.json() as typeof detailsBody;
        if (detailsBody?.item.state === 'review') {
          break;
        }
        await new Promise((resolve) => setTimeout(resolve, 100));
      }

      expect(detailsBody?.item.state).toBe('review');
      expect(detailsBody?.item.linkedRunId).toBe(replacementRunRecord?.id ?? null);
      expect(detailsBody?.item.delivery?.status).toBe('review');
      expect(detailsBody?.item.delivery?.metadata.latestDelegatedRun?.runId).toBe(replacementRunRecord?.id ?? null);
      expect(detailsBody?.item.delivery?.metadata.artifacts?.changedFiles).toContain('contact-final.txt');

      const receiptMessages = inspectDb
        .listMessages(sourceSession.id, 50)
        .filter((entry) => entry.direction === 'outbound')
        .map((entry) => ({
          metadata: JSON.parse(entry.metadataJson) as { command?: string; delegatedRunId?: string }
        }))
        .filter((entry) => entry.metadata.command === 'backlog_receipt');
      expect(receiptMessages.some((entry) => entry.metadata.delegatedRunId === delegatedRunId)).toBe(false);
      expect(receiptMessages.some((entry) => entry.metadata.delegatedRunId === replacementRunRecord?.id)).toBe(true);
    } finally {
      await customApp.close();
    }
  }, 30_000);

  it('sends Telegram typing indicators while a Telegram run is active', async () => {
    const originalFetch = globalThis.fetch;
    const fetchMock = vi.fn(async (input: URL | RequestInfo) => {
      const url = typeof input === 'string' ? input : input instanceof URL ? input.toString() : input.url;
      if (url.includes('api.telegram.org') && url.includes('/getUpdates')) {
        return new Response(JSON.stringify({ ok: true, result: [] }), {
          status: 200,
          headers: { 'content-type': 'application/json' }
        });
      }
      if (url.includes('api.telegram.org') && url.includes('/sendChatAction')) {
        return new Response(JSON.stringify({ ok: true, result: true }), {
          status: 200,
          headers: { 'content-type': 'application/json' }
        });
      }
      if (url.includes('api.telegram.org') && url.includes('/sendMessage')) {
        return new Response(
          JSON.stringify({
            ok: true,
            result: { message_id: 1 }
          }),
          {
            status: 200,
            headers: { 'content-type': 'application/json' }
          }
        );
      }
      throw new Error(`Unexpected fetch url: ${url}`);
    });
    vi.stubGlobal('fetch', fetchMock);
    const isolatedRoot = fs.mkdtempSync(path.join(os.tmpdir(), 'ops-gateway-typing-'));
    fs.mkdirSync(path.join(isolatedRoot, 'skills'), { recursive: true });
    const localConfig = structuredClone(config) as any;
    localConfig.runtime.workspaceRoot = isolatedRoot;
    localConfig.persistence.sqlitePath = path.join(isolatedRoot, 'state.db');
    localConfig.channel.telegram.botToken = '123456:abcdefghijklmnopqrstuvwxyzABCD';
    localConfig.channel.telegram.enabled = true;
    localConfig.channel.telegram.useWebhook = false;
    localConfig.runtime.adapters.process = {
      command: 'node',
      args: [
        '-e',
        'const f=require(\"node:fs\");let p=\"\";const extract=s=>{const i=s.lastIndexOf(\"CURRENT_TASK:\\n\");if(i>=0)return s.slice(i+14).trim();const t=s.lastIndexOf(\"TASK:\");return t>=0?s.slice(t+5).trim():s.trim()};const finish=o=>{f.writeFileSync(1,o);process.exit(0)};process.stdin.on(\"data\",c=>p+=c);process.stdin.on(\"end\",()=>setTimeout(()=>finish((extract(p)||\"ok\")+\" done\"),300));'
      ]
    };
    const localRuntimeConfigPath = path.join(isolatedRoot, 'runtime-config.json');
    fs.writeFileSync(localRuntimeConfigPath, JSON.stringify(localConfig, null, 2));

    const isolatedApp = await buildGatewayApp(localConfig, {
      runtimeConfigPath: localRuntimeConfigPath,
      skillRegistryRunner: skillInstallRunner
    });

    try {
      const bootstrapBaseline = await isolatedApp.inject({
        method: 'POST',
        url: '/api/onboarding/ceo-baseline',
        headers: {
          Authorization: `Bearer ${localConfig.server.apiToken}`,
          'x-ops-role': 'operator'
        },
        payload: {
          actor: 'typing-test'
        }
      });
      expect(bootstrapBaseline.statusCode).toBe(200);

      const senderId = 7522;
      const setupRuntime = await isolatedApp.inject({
        method: 'POST',
        url: '/api/ingress/telegram',
        payload: {
          update_id: 75220,
          message: {
            text: '/runtime process',
            chat: { id: senderId, type: 'private' },
            from: { id: senderId, username: 'typingprobe' },
            mentioned: true
          }
        }
      });
      expect(setupRuntime.statusCode).toBe(200);

      const queued = await isolatedApp.inject({
        method: 'POST',
        url: '/api/ingress/telegram',
        payload: {
          update_id: 75221,
          message: {
            text: 'Show typing indicator while you run.',
            chat: { id: senderId, type: 'private' },
            from: { id: senderId, username: 'typingprobe' },
            mentioned: true
          }
        }
      });
      expect(queued.statusCode).toBe(200);
      const queuedBody = queued.json() as { status: string; runId: string };
      expect(queuedBody.status).toBe('queued');

      const deadline = Date.now() + 10_000;
      let reachedTerminal = false;
      while (Date.now() < deadline) {
        const runResponse = await isolatedApp.inject({
          method: 'GET',
          url: `/api/runs/${queuedBody.runId}`,
          headers: {
            Authorization: `Bearer ${localConfig.server.apiToken}`
          }
        });
        expect(runResponse.statusCode).toBe(200);
        const runBody = runResponse.json() as { run: { status: string } };
        if (['completed', 'failed', 'aborted'].includes(runBody.run.status)) {
          reachedTerminal = true;
          break;
        }
        await new Promise((resolve) => setTimeout(resolve, 100));
      }
      expect(reachedTerminal).toBe(true);

      const urls = fetchMock.mock.calls
        .map(([input]) => (typeof input === 'string' ? input : input instanceof URL ? input.toString() : input.url))
        .filter((url): url is string => typeof url === 'string');
      expect(urls.some((url) => url.includes('/sendChatAction'))).toBe(true);
      expect(urls.some((url) => url.includes('/sendMessage'))).toBe(true);
    } finally {
      await isolatedApp.close();
      vi.stubGlobal('fetch', originalFetch);
    }
  }, 20_000);

  it('suppresses raw internal tool chatter from Telegram live drafts during provider-backed command runs', async () => {
    const previousFetch = globalThis.fetch;
    const previousGoogleApiKey = process.env.GOOGLE_API_KEY;
    process.env.GOOGLE_API_KEY = 'integration-google-key';

    const isolatedRoot = fs.mkdtempSync(path.join(os.tmpdir(), 'ops-gateway-telegram-live-safe-'));
    fs.mkdirSync(path.join(isolatedRoot, 'skills'), { recursive: true });
    const localConfig = structuredClone(config) as typeof config;
    localConfig.runtime.defaultRuntime = 'process';
    localConfig.runtime.workspaceRoot = isolatedRoot;
    localConfig.persistence.sqlitePath = path.join(isolatedRoot, 'state.db');
    localConfig.channel.telegram.botToken = validTelegramBotToken;
    localConfig.channel.telegram.enabled = true;
    localConfig.channel.telegram.useWebhook = false;
    localConfig.channel.telegram.debugRawOutput = false;
    const localRuntimeConfigPath = path.join(isolatedRoot, 'runtime-config.json');
    fs.writeFileSync(localRuntimeConfigPath, JSON.stringify(localConfig, null, 2));

    const telegramDrafts: string[] = [];
    const telegramSends: string[] = [];
    const telegramEdits: string[] = [];
    const telegramTyping: string[] = [];
    let googleCalls = 0;
    const chatterScript = [
      "process.stdout.write('[native_tool_session:live-test] skill_call[skill] internal-skill invoked\\n');",
      "setTimeout(() => process.stdout.write('Skill internal-skill (Internal helper)\\n# Internal Skill\\n\\nThis should stay out of Telegram drafts.\\n'), 150);",
      'setTimeout(() => process.exit(0), 1500);'
    ].join('');
    const fetchMock = vi.fn(async (input: URL | RequestInfo, init?: RequestInit) => {
      const url = typeof input === 'string' ? input : input instanceof URL ? input.toString() : input.url;
      if (url.includes('api.telegram.org')) {
        const method = url.split('/').pop() ?? '';
        const body = init?.body ? (JSON.parse(String(init.body)) as { text?: string }) : {};
        if (method === 'getUpdates') {
          return new Response(JSON.stringify({ ok: true, result: [] }), {
            status: 200,
            headers: { 'content-type': 'application/json' }
          });
        }
        if (method === 'sendChatAction') {
          telegramTyping.push(method);
          return new Response(JSON.stringify({ ok: true, result: true }), {
            status: 200,
            headers: { 'content-type': 'application/json' }
          });
        }
        if (method === 'sendMessageDraft') {
          telegramDrafts.push(String(body.text ?? ''));
          return new Response(JSON.stringify({ ok: true, result: true }), {
            status: 200,
            headers: { 'content-type': 'application/json' }
          });
        }
        if (method === 'editMessageText') {
          telegramEdits.push(String(body.text ?? ''));
          return new Response(JSON.stringify({ ok: true, result: { message_id: 1 } }), {
            status: 200,
            headers: { 'content-type': 'application/json' }
          });
        }
        if (method === 'sendMessage') {
          telegramSends.push(String(body.text ?? ''));
          return new Response(JSON.stringify({ ok: true, result: { message_id: telegramSends.length || 1 } }), {
            status: 200,
            headers: { 'content-type': 'application/json' }
          });
        }
        if (method === 'deleteMyCommands' || method === 'setMyCommands') {
          return new Response(JSON.stringify({ ok: true, result: true }), {
            status: 200,
            headers: { 'content-type': 'application/json' }
          });
        }
        throw new Error(`Unexpected Telegram fetch url: ${url}`);
      }
      if (url.includes('generativelanguage.googleapis.com')) {
        googleCalls += 1;
        if (googleCalls === 1) {
          return new Response(
            JSON.stringify({
              candidates: [
                {
                  content: {
                    parts: [
                      {
                        functionCall: {
                          id: 'gemini-telegram-live-safe-1',
                          name: 'execute_command',
                          args: {
                            argv: ['node', '-e', chatterScript],
                            reason: 'Run the requested command and report back.'
                          }
                        }
                      }
                    ]
                  }
                }
              ],
              usageMetadata: {
                promptTokenCount: 18,
                candidatesTokenCount: 12,
                totalTokenCount: 30
              }
            }),
            {
              status: 200,
              headers: { 'content-type': 'application/json' }
            }
          );
        }
        return new Response(
          JSON.stringify({
            candidates: [
              {
                content: {
                  parts: [
                    {
                      text: 'Clean final answer after verified execution.'
                    }
                  ]
                }
              }
            ],
            usageMetadata: {
              promptTokenCount: 12,
              candidatesTokenCount: 9,
              totalTokenCount: 21
            }
          }),
          {
            status: 200,
            headers: { 'content-type': 'application/json' }
          }
        );
      }
      throw new Error(`Unexpected fetch url: ${url}`);
    });
    vi.stubGlobal('fetch', fetchMock);

    const isolatedApp = await buildGatewayApp(localConfig, {
      runtimeConfigPath: localRuntimeConfigPath,
      skillRegistryRunner: skillInstallRunner
    });
    const localInject = async (options: Parameters<typeof isolatedApp.inject>[0]) => {
      const headers = { ...(options.headers ?? {}) } as Record<string, string>;
      if (!headers.Authorization) {
        headers.Authorization = `Bearer ${localConfig.server.apiToken}`;
      }
      if (!headers['x-ops-role']) {
        headers['x-ops-role'] = 'operator';
      }
      return isolatedApp.inject({
        ...options,
        headers
      });
    };

    try {
      const bootstrapBaseline = await localInject({
        method: 'POST',
        url: '/api/onboarding/ceo-baseline',
        payload: {
          actor: 'telegram-live-safe-test'
        }
      });
      expect(bootstrapBaseline.statusCode).toBe(200);

      const senderId = 9211;
      const setModel = await isolatedApp.inject({
        method: 'POST',
        url: '/api/ingress/telegram',
        payload: {
          update_id: 92110,
          message: {
            text: '/model gemini-2.5-pro',
            chat: { id: senderId, type: 'private' },
            from: { id: senderId, username: 'livesafe' },
            mentioned: true
          }
        }
      });
      expect(setModel.statusCode).toBe(200);
      telegramDrafts.length = 0;
      telegramSends.length = 0;
      telegramEdits.length = 0;
      telegramTyping.length = 0;

      const queued = await isolatedApp.inject({
        method: 'POST',
        url: '/api/ingress/telegram',
        payload: {
          update_id: 92111,
          message: {
            text: 'Run the internal diagnostic command.',
            chat: { id: senderId, type: 'private' },
            from: { id: senderId, username: 'livesafe' },
            mentioned: true
          }
        }
      });
      expect(queued.statusCode).toBe(200);
      const queuedBody = queued.json() as { status: string; sessionId: string; runId: string };
      expect(queuedBody.status).toBe('queued');

      const finalRun = await waitForTerminalRunWithInject(localInject, queuedBody.runId, 15_000);
      expect(finalRun.status).toBe('completed');
      const outbound = await waitForOutboundMessageByRunWithInject(
        localInject,
        queuedBody.sessionId,
        queuedBody.runId,
        15_000
      );
      expect(outbound.content).toContain('Clean final answer after verified execution.');
      expect(googleCalls).toBe(2);
      expect(telegramTyping.length).toBeGreaterThan(0);
      expect(telegramDrafts.join('\n')).not.toContain('[native_tool_session:');
      expect(telegramDrafts.join('\n')).not.toContain('Skill internal-skill');
      expect(telegramDrafts.join('\n')).not.toContain('# Internal Skill');
      expect(telegramEdits.join('\n')).not.toContain('[native_tool_session:');
      expect(telegramEdits.join('\n')).not.toContain('Skill internal-skill');
      expect(telegramSends.join('\n')).toContain('Clean final answer after verified execution.');
    } finally {
      await isolatedApp.close();
      vi.stubGlobal('fetch', previousFetch);
      if (previousGoogleApiKey === undefined) {
        delete process.env.GOOGLE_API_KEY;
      } else {
        process.env.GOOGLE_API_KEY = previousGoogleApiKey;
      }
      fs.rmSync(isolatedRoot, { recursive: true, force: true });
    }
  }, 20_000);

