      expect(telegramLiveTexts.join('\n')).toContain('[native_tool_session:live-debug]');
      expect(telegramLiveTexts.join('\n')).toContain('Skill internal-skill');
      expect(telegramLiveTexts.join('\n')).toContain('# Internal Skill');
