  it('keeps blocked provider-backed skill runs free of raw Telegram tool chatter while preserving the final blocked reason', async () => {
    const previousFetch = globalThis.fetch;
    const previousGoogleApiKey = process.env.GOOGLE_API_KEY;
    process.env.GOOGLE_API_KEY = 'integration-google-key';

    const isolatedRoot = fs.mkdtempSync(path.join(os.tmpdir(), 'ops-gateway-telegram-live-blocked-'));
    const skillRoot = path.join(isolatedRoot, 'skills');
    const skillDir = path.join(skillRoot, 'blocked-live-skill');
    fs.mkdirSync(skillDir, { recursive: true });
    fs.writeFileSync(
      path.join(skillDir, 'SKILL.md'),
      [
        '---',
        'name: blocked-live-skill',
        'description: blocked skill used to prove telegram live drafts stay clean on policy errors',
        'allowedCommands:',
        '  - missing-live-tool',
        'requiredTools:',
        '  - missing-live-tool',
        '---',
        '',
        '# Blocked Live Skill',
        '',
        'This skill should never be callable in the runtime tool loop.'
      ].join('\n'),
      'utf-8'
    );

    const localConfig = structuredClone(config) as typeof config;
    localConfig.runtime.defaultRuntime = 'process';
    localConfig.runtime.workspaceRoot = isolatedRoot;
    localConfig.persistence.sqlitePath = path.join(isolatedRoot, 'state.db');
    localConfig.channel.telegram.botToken = validTelegramBotToken;
    localConfig.channel.telegram.enabled = true;
    localConfig.channel.telegram.useWebhook = false;
    localConfig.channel.telegram.debugRawOutput = false;
    const localRuntimeConfigPath = path.join(isolatedRoot, 'runtime-config.json');
    fs.writeFileSync(localRuntimeConfigPath, JSON.stringify(localConfig, null, 2));

    const telegramDrafts: string[] = [];
    const telegramSends: string[] = [];
    let googleCalls = 0;
    const fetchMock = vi.fn(async (input: URL | RequestInfo, init?: RequestInit) => {
      const url = typeof input === 'string' ? input : input instanceof URL ? input.toString() : input.url;
      if (url.includes('api.telegram.org')) {
        const method = url.split('/').pop() ?? '';
        const body = init?.body ? (JSON.parse(String(init.body)) as { text?: string }) : {};
        if (method === 'getUpdates') {
          return new Response(JSON.stringify({ ok: true, result: [] }), {
            status: 200,
            headers: { 'content-type': 'application/json' }
          });
        }
        if (method === 'sendChatAction') {
          return new Response(JSON.stringify({ ok: true, result: true }), {
            status: 200,
            headers: { 'content-type': 'application/json' }
          });
        }
        if (method === 'sendMessageDraft') {
          telegramDrafts.push(String(body.text ?? ''));
          return new Response(JSON.stringify({ ok: true, result: true }), {
            status: 200,
            headers: { 'content-type': 'application/json' }
          });
        }
        if (method === 'sendMessage') {
          telegramSends.push(String(body.text ?? ''));
          return new Response(JSON.stringify({ ok: true, result: { message_id: telegramSends.length || 1 } }), {
            status: 200,
            headers: { 'content-type': 'application/json' }
          });
        }
        if (method === 'editMessageText' || method === 'deleteMyCommands' || method === 'setMyCommands') {
          return new Response(JSON.stringify({ ok: true, result: { message_id: 1 } }), {
            status: 200,
            headers: { 'content-type': 'application/json' }
          });
        }
        throw new Error(`Unexpected Telegram fetch url: ${url}`);
      }
      if (url.includes('generativelanguage.googleapis.com')) {
        googleCalls += 1;
        if (googleCalls === 1) {
          return new Response(
            JSON.stringify({
              candidates: [
                {
                  content: {
                    parts: [
                      {
                        functionCall: {
                          id: 'gemini-telegram-live-blocked-1',
                          name: 'skill_call',
                          args: {
                            skill: 'blocked-live-skill',
                            payload: {
                              task: 'status'
                            },
                            reason: 'Consult the explicitly named skill first.'
                          }
                        }
                      }
                    ]
                  }
                }
              ],
              usageMetadata: {
                promptTokenCount: 18,
                candidatesTokenCount: 12,
                totalTokenCount: 30
              }
            }),
            {
              status: 200,
              headers: { 'content-type': 'application/json' }
            }
          );
        }
        return new Response(
          JSON.stringify({
            candidates: [
              {
                content: {
                  parts: [
                    {
                      text: 'Blocked final answer after policy denial.'
                    }
                  ]
                }
              }
            ],
            usageMetadata: {
              promptTokenCount: 12,
              candidatesTokenCount: 9,
              totalTokenCount: 21
            }
          }),
          {
            status: 200,
            headers: { 'content-type': 'application/json' }
          }
        );
      }
      throw new Error(`Unexpected fetch url: ${url}`);
    });
    vi.stubGlobal('fetch', fetchMock as unknown as typeof fetch);

    const isolatedApp = await buildGatewayApp(localConfig, {
      runtimeConfigPath: localRuntimeConfigPath,
      skillRegistryRunner: skillInstallRunner
    });
    const localInject = async (options: Parameters<typeof isolatedApp.inject>[0]) => {
      const headers = { ...(options.headers ?? {}) } as Record<string, string>;
      if (!headers.Authorization) {
        headers.Authorization = `Bearer ${localConfig.server.apiToken}`;
      }
      if (!headers['x-ops-role']) {
        headers['x-ops-role'] = 'operator';
      }
      return isolatedApp.inject({
        ...options,
        headers
      });
    };

    try {
      const bootstrapBaseline = await localInject({
        method: 'POST',
        url: '/api/onboarding/ceo-baseline',
        payload: {
          actor: 'telegram-live-blocked-test'
        }
      });
      expect(bootstrapBaseline.statusCode).toBe(200);

      const upserted = await localInject({
        method: 'POST',
        url: '/api/skills/catalog/entries/upsert',
        payload: {
          path: skillDir,
          approved: true
        }
      });
      expect(upserted.statusCode).toBe(200);

      const senderId = 9213;
      const setModel = await isolatedApp.inject({
        method: 'POST',
        url: '/api/ingress/telegram',
        payload: {
          update_id: 92130,
          message: {
            text: '/model gemini-2.5-pro',
            chat: { id: senderId, type: 'private' },
            from: { id: senderId, username: 'liveblocked' },
            mentioned: true
          }
        }
      });
      expect(setModel.statusCode).toBe(200);
      telegramDrafts.length = 0;
      telegramSends.length = 0;

      const queued = await isolatedApp.inject({
        method: 'POST',
        url: '/api/ingress/telegram',
        payload: {
          update_id: 92131,
          message: {
            text: 'Use blocked-live-skill for this task.',
            chat: { id: senderId, type: 'private' },
            from: { id: senderId, username: 'liveblocked' },
            mentioned: true
          }
        }
      });
      expect(queued.statusCode).toBe(200);
      const queuedBody = queued.json() as { status: string; sessionId: string; runId: string };
      expect(queuedBody.status).toBe('queued');

      const finalRun = await waitForTerminalRunWithInject(localInject, queuedBody.runId, 15_000);
      expect(finalRun.status).toBe('completed');
      const outbound = await waitForOutboundMessageByRunWithInject(
        localInject,
        queuedBody.sessionId,
        queuedBody.runId,
        15_000
      );
      expect(outbound.content).toContain('Blocked final answer after policy denial.');
      expect(googleCalls).toBe(2);
      expect(telegramDrafts.join('\n')).not.toContain('[skill]');
      expect(telegramDrafts.join('\n')).not.toContain('Blocked Live Skill');
      expect(telegramSends.join('\n')).toContain('Blocked final answer after policy denial.');
    } finally {
      await isolatedApp.close();
      vi.stubGlobal('fetch', previousFetch);
      if (previousGoogleApiKey === undefined) {
        delete process.env.GOOGLE_API_KEY;
      } else {
        process.env.GOOGLE_API_KEY = previousGoogleApiKey;
      }
      fs.rmSync(isolatedRoot, { recursive: true, force: true });
    }
  }, 20_000);

