      expect(outbound?.content).toContain('Followers 15.2K');
      expect(telegramDrafts.join('\n')).not.toContain('Skill not found in autonomous catalog');
      expect(telegramSends.join('\n')).toContain('Verified browser capture for @minilanoy');

