  it('surfaces placeholder process adapter diagnostics in config validation and readiness', async () => {
    const runtimeConfig = await inject({
      method: 'GET',
      url: '/api/config/runtime',
      headers: {
        Authorization: `Bearer ${config.server.apiToken}`
      }
    });
    expect(runtimeConfig.statusCode).toBe(200);
    const runtimeConfigBody = runtimeConfig.json() as {
      config: Record<string, unknown>;
    };
    const nextConfig = structuredClone(runtimeConfigBody.config) as Record<string, unknown>;
    const runtime = (nextConfig.runtime as Record<string, unknown>) ?? {};
    const adapters = (runtime.adapters as Record<string, unknown>) ?? {};
    adapters.process = {
      command: 'node',
      args: ['scripts/runtime/process-fail-closed.mjs']
    };
    runtime.adapters = adapters;
    nextConfig.runtime = runtime;
    const saveRuntimeConfig = await inject({
      method: 'PUT',
      url: '/api/config/runtime',
      headers: {
        Authorization: `Bearer ${config.server.apiToken}`
      },
      payload: {
        config: nextConfig,
        actor: 'test'
      }
    });
    expect(saveRuntimeConfig.statusCode).toBe(200);

    const validation = await inject({
      method: 'GET',
      url: '/api/config/validate',
      headers: {
        Authorization: `Bearer ${config.server.apiToken}`
      }
    });
    expect(validation.statusCode).toBe(200);
    const validationBody = validation.json() as {
      validation: {
        warnings: Array<{ path: string; code: string; message: string }>;
      };
    };
    expect(
      validationBody.validation.warnings.some(
        (issue) => issue.path === 'runtime.adapters.process' && issue.code === 'process_adapter_placeholder'
      )
    ).toBe(true);

    const readiness = await inject({
      method: 'GET',
      url: '/api/health/readiness'
    });
    expect(readiness.statusCode).toBe(200);
    const readinessBody = readiness.json() as {
      readiness: {
        checks: Array<{ name: string; summary: string; details?: { processAdapterPlaceholder?: boolean } }>;
      };
    };
    const runtimeRegistry = readinessBody.readiness.checks.find((check) => check.name === 'runtime_registry');
    expect(runtimeRegistry?.summary).toContain('Process uses the default fail-closed placeholder');
    expect(runtimeRegistry?.details?.processAdapterPlaceholder).toBe(true);
  });

