  it('records prompt assembly snapshots and continuity signals for overflow preflight and bounded retry', async () => {
    const localRoot = fs.mkdtempSync(path.join(os.tmpdir(), 'ops-gateway-continuity-'));
    fs.mkdirSync(path.join(localRoot, 'skills'), { recursive: true });

    const localConfig = structuredClone(config) as any;
    localConfig.runtime.workspaceRoot = localRoot;
    localConfig.persistence.sqlitePath = path.join(localRoot, 'state.db');
    localConfig.skills.directories = [path.join(localRoot, 'skills')];
    localConfig.runtime.contextAssembly = {
      enabled: true,
      totalTokenBudget: 4096,
      overflowStrategy: 'shrink',
      transcriptWindowTurns: 2,
      transcriptMaxMessages: 8,
      memoryTopK: 0,
      memoryMinScore: 0,
      reserves: {
        instructions: 1200,
        task: 1500,
        recentTranscript: 800,
        memoryRecall: 200
      },
      dropOrder: ['memory_recall', 'recent_transcript', 'instructions']
    };
    localConfig.runtime.adapters.process = {
      command: 'node',
      args: ['-e', 'process.stderr.write("context window overflow\\n");process.exit(1);']
    };

    const localApp = await buildGatewayApp(localConfig as never, {
      skillRegistryRunner: skillInstallRunner
    });
    const localInject = async (options: Parameters<typeof localApp.inject>[0]) => {
      if (typeof options === 'string') {
        return localApp.inject(options);
      }
      const headers = { ...(options.headers ?? {}) } as Record<string, string>;
      const hasAuth = Boolean(headers.Authorization || headers.authorization || headers['x-api-token']);
      if (String(options.url ?? '').startsWith('/api/') && !hasAuth) {
        headers.Authorization = `Bearer ${localConfig.server.apiToken}`;
      }
      if (String(options.url ?? '').startsWith('/api/') && !headers['x-ops-role']) {
        headers['x-ops-role'] = 'operator';
      }
      return localApp.inject({
        ...options,
        headers
      });
    };

    try {
      const bootstrapBaseline = await localInject({
        method: 'POST',
        url: '/api/onboarding/ceo-baseline',
        payload: {
          actor: 'continuity-test'
        }
      });
      expect(bootstrapBaseline.statusCode).toBe(200);

      const created = await localInject({
        method: 'POST',
        url: '/api/sessions',
        payload: {
          label: 'continuity-runtime-overflow',
          agentId: 'ceo-default',
          runtime: 'process',
          model: 'default'
        }
      });
      expect(created.statusCode).toBe(201);
      const createdBody = created.json() as { session: { id: string } };

      const runResponse = await localInject({
        method: 'POST',
        url: `/api/sessions/${createdBody.session.id}/runs`,
        headers: {
          'Idempotency-Key': 'continuity-runtime-overflow'
        },
        payload: {
          prompt: 'trigger runtime overflow retry',
          runtime: 'process'
        }
      });
      expect(runResponse.statusCode).toBe(201);
      const runBody = runResponse.json() as { run: { id: string } };

      const deadline = Date.now() + 15_000;
      let terminalRun: { status: string; error: string | null } | null = null;
      while (Date.now() < deadline) {
        const runDetails = await localInject({
          method: 'GET',
          url: `/api/runs/${runBody.run.id}`
        });
        expect(runDetails.statusCode).toBe(200);
        const runPayload = runDetails.json() as { run: { status: string; error: string | null } };
        if (['completed', 'failed', 'aborted'].includes(runPayload.run.status)) {
          terminalRun = runPayload.run;
          break;
        }
        await new Promise((resolve) => setTimeout(resolve, 120));
      }
      expect(terminalRun).toBeTruthy();
      expect(['completed', 'failed', 'aborted']).toContain(terminalRun?.status ?? '');

      const snapshot = await localInject({
        method: 'GET',
        url: `/api/runs/${runBody.run.id}/prompt-assembly`
      });
      expect(snapshot.statusCode).toBe(200);
      const snapshotBody = snapshot.json() as {
        snapshot: { totalEstimatedTokens: number; contextLimit: number; segments: unknown[] };
      };
      expect(snapshotBody.snapshot.totalEstimatedTokens).toBeGreaterThan(0);
      expect(snapshotBody.snapshot.contextLimit).toBeGreaterThan(0);
      expect(Array.isArray(snapshotBody.snapshot.segments)).toBe(true);

      const overflowSignalCreate = await localInject({
        method: 'POST',
        url: '/api/continuity/signals',
        payload: {
          runId: runBody.run.id,
          sessionId: createdBody.session.id,
          source: 'runtime_adapter',
          code: 'context_overflow_runtime',
          severity: 'high',
          summary: 'Simulated runtime overflow signal for continuity pipeline test',
          details: {
            test: true
          }
        }
      });
      expect(overflowSignalCreate.statusCode).toBe(201);
      const overflowSignalCreateBody = overflowSignalCreate.json() as {
        signal: { id: string; code: string; status: string };
      };
      expect(overflowSignalCreateBody.signal.code).toBe('context_overflow_runtime');

      const exhaustedSignalCreate = await localInject({
        method: 'POST',
        url: '/api/continuity/signals',
        payload: {
          runId: runBody.run.id,
          sessionId: createdBody.session.id,
          source: 'continuity_remediation',
          code: 'retry_exhausted',
          severity: 'high',
          summary: 'Simulated retry exhausted signal for continuity pipeline test',
          details: {
            test: true
          }
        }
      });
      expect(exhaustedSignalCreate.statusCode).toBe(201);
      const exhaustedSignalCreateBody = exhaustedSignalCreate.json() as {
        signal: { id: string; code: string; status: string };
      };
      expect(exhaustedSignalCreateBody.signal.code).toBe('retry_exhausted');
      expect(exhaustedSignalCreateBody.signal.status).toBe('open');

      const resolveSignal = await localInject({
        method: 'POST',
        url: `/api/continuity/signals/${exhaustedSignalCreateBody.signal.id}/resolve`
      });
      expect(resolveSignal.statusCode).toBe(200);
      const resolveBody = resolveSignal.json() as { signal: { status: string } };
      expect(resolveBody.signal.status).toBe('resolved');
    } finally {
      await localApp.close();
    }
  }, 30_000);

  it('treats timed-out codex runs as terminal failures without queue retries', async () => {
    const localRoot = fs.mkdtempSync(path.join(os.tmpdir(), 'ops-gateway-timeout-'));
    fs.mkdirSync(path.join(localRoot, 'skills'), { recursive: true });

    const localConfig = structuredClone(config) as any;
    localConfig.runtime.workspaceRoot = localRoot;
    localConfig.persistence.sqlitePath = path.join(localRoot, 'state.db');
    localConfig.skills.directories = [path.join(localRoot, 'skills')];
    localConfig.runtime.adapters.codex = {
      command: 'node',
      args: ['-e', 'setTimeout(() => process.exit(0), 8000);']
    };

    const localApp = await buildGatewayApp(localConfig as never, {
      skillRegistryRunner: skillInstallRunner
    });
    const localInject = async (options: Parameters<typeof localApp.inject>[0]) => {
      if (typeof options === 'string') {
        return localApp.inject(options);
      }
      const headers = { ...(options.headers ?? {}) } as Record<string, string>;
      const hasAuth = Boolean(headers.Authorization || headers.authorization || headers['x-api-token']);
      if (String(options.url ?? '').startsWith('/api/') && !hasAuth) {
        headers.Authorization = `Bearer ${localConfig.server.apiToken}`;
      }
      if (String(options.url ?? '').startsWith('/api/') && !headers['x-ops-role']) {
        headers['x-ops-role'] = 'operator';
      }
      return localApp.inject({
        ...options,
        headers
      });
    };

    try {
      const bootstrapBaseline = await localInject({
        method: 'POST',
        url: '/api/onboarding/ceo-baseline',
        payload: {
          actor: 'timeout-test'
        }
      });
      expect(bootstrapBaseline.statusCode).toBe(200);

      const limitsResponse = await localInject({
        method: 'GET',
        url: '/api/llm/limits'
      });
      expect(limitsResponse.statusCode).toBe(200);
      const limitsBody = limitsResponse.json() as { limits: Record<string, any> };
      const nextLimits = structuredClone(limitsBody.limits) as Record<string, any>;
      nextLimits.localHarnessByRuntime.codex = true;
      nextLimits.orchestratorLocalHarnessByRuntime.codex = true;
      const saveLimits = await localInject({
        method: 'PUT',
        url: '/api/llm/limits',
        payload: {
          actor: 'timeout-test',
          limits: nextLimits
        }
      });
      expect(saveLimits.statusCode).toBe(200);

      const created = await localInject({
        method: 'POST',
        url: '/api/sessions',
        payload: {
          label: 'codex-timeout-terminal',
          agentId: 'software-engineer',
          runtime: 'codex',
          model: 'default'
        }
      });
      expect(created.statusCode).toBe(201);
      const createdBody = created.json() as { session: { id: string } };

      const setOverrides = await localInject({
        method: 'PATCH',
        url: `/api/sessions/${createdBody.session.id}/preferences`,
        payload: {
          runtimeOverrides: {
            timeoutMs: 1_000
          }
        }
      });
      expect(setOverrides.statusCode).toBe(200);

      const runResponse = await localInject({
        method: 'POST',
        url: `/api/sessions/${createdBody.session.id}/runs`,
        headers: {
          'Idempotency-Key': 'codex-timeout-terminal'
        },
        payload: {
          prompt: 'force timeout terminal-state check',
          runtime: 'codex',
          model: 'default'
        }
      });
      expect(runResponse.statusCode).toBe(201);
      const runBody = runResponse.json() as { run: { id: string } };

      const terminalDeadline = Date.now() + 15_000;
      let terminalRun: { status: string; error: string | null } | null = null;
      while (Date.now() < terminalDeadline) {
        const runDetails = await localInject({
          method: 'GET',
          url: `/api/runs/${runBody.run.id}`
        });
        expect(runDetails.statusCode).toBe(200);
        const runPayload = runDetails.json() as { run: { status: string; error: string | null } };
        if (['completed', 'failed', 'aborted'].includes(runPayload.run.status)) {
          terminalRun = runPayload.run;
          break;
        }
        await new Promise((resolve) => setTimeout(resolve, 120));
      }
      expect(terminalRun).toBeTruthy();
      expect(terminalRun?.status).toBe('failed');
      expect(String(terminalRun?.error ?? '').toLowerCase()).toContain('timeout');

      const queueBody = await waitForQueueToClearRun(runBody.run.id, 10_000);
      expect(queueBody.processing.some((entry) => entry.runId === runBody.run.id)).toBe(false);
      expect(queueBody.deadLetter.some((entry) => entry.runId === runBody.run.id)).toBe(false);

      const timeline = await localInject({
        method: 'GET',
        url: `/api/runs/${runBody.run.id}/timeline`
      });
      expect(timeline.statusCode).toBe(200);
      const timelineBody = timeline.json() as {
        timeline: Array<{ type: string }>;
      };
      const acceptedCount = timelineBody.timeline.filter((event) => event.type === 'run.accepted').length;
      const runningCount = timelineBody.timeline.filter((event) => event.type === 'run.running').length;
      const failedCount = timelineBody.timeline.filter((event) => event.type === 'run.failed').length;
      expect(acceptedCount).toBe(1);
      expect(runningCount).toBe(1);
      expect(failedCount).toBe(1);
    } finally {
      await localApp.close();
    }
  }, 35_000);

