        '  exit 2',
        'fi',
        'shift',
        'if [ "${1:-}" = "--help" ] || [ "${1:-}" = "-h" ]; then',
        '  cat <<\'EOF\'',
        'Usage: querytool-preflight search [OPTIONS] QUERY',
        '',
        'Options:',
        '  --sentiment',
        '  --limit INTEGER',
        '  --help',
        'EOF',
        '  exit 0',
        'fi',
        'query=""',
        'seen_query=0',
        'while [ "$#" -gt 0 ]; do',
        '  case "$1" in',
        '    --sentiment)',
        '      shift',
        '      ;;',
        '    --limit)',
        '      shift 2',
        '      ;;',
        '    --*)',
        '      echo "Usage: querytool-preflight search [OPTIONS] QUERY" >&2',
        '      echo "Error: No such option: $1" >&2',
        '      exit 2',
        '      ;;',
        '    *)',
        '      if [ "$seen_query" -eq 1 ]; then',
