  it('reuses persisted native tool-session handles on run-control resume and exposes lifecycle state on the session API', async () => {
    const originalFetch = globalThis.fetch;
    const originalOpenRouterKey = process.env.OPENROUTER_API_KEY;
    process.env.OPENROUTER_API_KEY = 'integration-openrouter-key';

    let openRouterCalls = 0;
    const fetchMock = vi.fn(async (input: unknown) => {
      const url = String(input ?? '');
      if (!url.includes('openrouter.ai/api/v1/chat/completions')) {
        return new Response(JSON.stringify({ ok: true }), {
          status: 200,
          headers: { 'content-type': 'application/json' }
        });
      }
      openRouterCalls += 1;
      return new Response(
        JSON.stringify({
          id: `chatcmpl-native-resume-${openRouterCalls}`,
          choices: [
            {
              message: {
                ...(openRouterCalls === 2
                  ? {
                      content: 'Final answer after first native skill call.'
                    }
                  : {
                      content: '',
                      tool_calls: [
                        {
                          id: `call_skill_resume_${openRouterCalls}`,
                          function: {
                            name: 'skill_call',
                            arguments: JSON.stringify({
                              skill: 'installed-skill',
                              payload: {
                                smoke: true,
                                iteration: openRouterCalls
                              },
                              reason: openRouterCalls === 1 ? 'Need the skill first.' : 'Resume the same skill session.'
                            })
                          }
                        }
                      ]
                    })
              }
            }
          ]
        }),
        {
          status: 200,
          headers: {
            'content-type': 'application/json'
          }
        }
      );
    });
    vi.stubGlobal('fetch', fetchMock as unknown as typeof fetch);

    let previousExecutionMode: 'on_demand' | 'persistent_harness' | 'dispatch_only' = 'on_demand';
    let installedSkill = false;
    try {
      const profilesResponse = await inject({
        method: 'GET',
        url: '/api/agents/profiles'
      });
      expect(profilesResponse.statusCode).toBe(200);
      const profilesBody = profilesResponse.json() as {
        agents: Array<{ id: string; executionMode: 'on_demand' | 'persistent_harness' | 'dispatch_only' }>;
      };
      previousExecutionMode = profilesBody.agents.find((agent) => agent.id === 'ceo-default')?.executionMode ?? 'on_demand';

      const setOnDemand = await inject({
        method: 'PATCH',
        url: '/api/agents/profiles/ceo-default',
        headers: {
          Authorization: `Bearer ${config.server.apiToken}`
        },
        payload: {
          executionMode: 'on_demand'
        }
      });
      expect(setOnDemand.statusCode).toBe(200);

      const install = await inject({
        method: 'POST',
        url: '/api/skills/install',
        headers: {
          Authorization: `Bearer ${config.server.apiToken}`
        },
        payload: {
          source: 'vercel-labs/agent-skills',
          approved: true
        }
      });
      expect(install.statusCode).toBe(200);
      installedSkill = true;

      const created = await inject({
        method: 'POST',
        url: '/api/sessions',
        headers: {
          Authorization: `Bearer ${config.server.apiToken}`
        },
        payload: {
          label: 'ceo-native-resume-run',
          agentId: 'ceo-default',
          runtime: 'process',
          model: 'openrouter/free'
        }
      });
      expect(created.statusCode).toBe(201);
      const session = created.json() as { session: { id: string } };

      const queued = await inject({
        method: 'POST',
        url: `/api/sessions/${session.session.id}/runs`,
        headers: {
          Authorization: `Bearer ${config.server.apiToken}`,
          'Idempotency-Key': 'ceo-native-resume-run'
        },
        payload: {
          prompt: 'Use the installed skill before answering.',
          runtime: 'process',
          model: 'openrouter/free',
          autoDelegate: false
        }
      });
      expect(queued.statusCode).toBe(201);
      const queuedBody = queued.json() as { run: { id: string } };

      const firstRun = await waitForTerminalRun(queuedBody.run.id);
      expect(firstRun.status).toBe('completed');

      const firstRunResponse = await inject({
        method: 'GET',
        url: `/api/runs/${queuedBody.run.id}`
      });
      expect(firstRunResponse.statusCode).toBe(200);
      const firstRunBody = firstRunResponse.json() as {
        nativeToolSession: { handleId: string } | null;
      };
      expect(firstRunBody.nativeToolSession?.handleId).toBeTruthy();

      const db = new ControlPlaneDatabase(path.join(root, 'state.db'));
      const resumeRun = db.createRun({
        sessionId: session.session.id,
        runtime: 'process',
        requestedRuntime: 'process',
        requestedModel: 'openrouter/free',
        effectiveRuntime: 'process',
        effectiveModel: 'openrouter/free',
        triggerSource: 'resume_test',
        supersedesRunId: queuedBody.run.id,
        prompt: 'Resume the same native tool session.',
        status: 'waiting_input'
      });
      db.close();

      const resumed = await inject({
        method: 'POST',
        url: `/api/runs/${resumeRun.id}/resume`,
        headers: {
          Authorization: `Bearer ${config.server.apiToken}`
        },
        payload: {
          actor: 'test',
          prompt: 'Resume the same native tool session.'
        }
      });
      expect(resumed.statusCode).toBe(200);
      const resumedBody = resumed.json() as {
        run: { status: string };
      };
      expect(['completed', 'waiting_input', 'failed']).toContain(resumedBody.run.status);

      const resumedRunResponse = await inject({
        method: 'GET',
        url: `/api/runs/${resumeRun.id}`
      });
      expect(resumedRunResponse.statusCode).toBe(200);
      const resumedRunBody = resumedRunResponse.json() as {
        nativeToolSession: {
          handleId: string;
          version: number;
          resumedFromRunId: string | null;
          resumeSource: string | null;
        } | null;
        lifecycle: {
          gatewayRunning: boolean;
          ownership: { gatewayAuthority: string };
          executorLane: {
            toolSessionMode: string | null;
            nativeToolSessionHandleId: string | null;
          };
        } | null;
        timeline: Array<{ type: string; payloadJson: string }>;
      };
      expect(resumedRunBody.nativeToolSession?.handleId).toBe(firstRunBody.nativeToolSession?.handleId);
      expect((resumedRunBody.nativeToolSession?.version ?? 0)).toBeGreaterThan(1);
      expect(resumedRunBody.nativeToolSession?.resumedFromRunId).toBe(queuedBody.run.id);
      expect(resumedRunBody.nativeToolSession?.resumeSource).toBe('run_control_resume');
      expect(resumedRunBody.lifecycle?.gatewayRunning).toBe(true);
      expect(resumedRunBody.lifecycle?.ownership.gatewayAuthority).toBe('service');
      expect(resumedRunBody.lifecycle?.executorLane.toolSessionMode).toBe('native_tool_session');
      expect(resumedRunBody.lifecycle?.executorLane.nativeToolSessionHandleId).toBe(firstRunBody.nativeToolSession?.handleId ?? null);
      expect(resumedRunBody.timeline.some((entry) => entry.type === 'session_resumed')).toBe(true);

      const sessionResponse = await inject({
        method: 'GET',
        url: `/api/sessions/${session.session.id}`
      });
      expect(sessionResponse.statusCode).toBe(200);
      const sessionBody = sessionResponse.json() as {
        session: {
          lifecycle: {
            gatewayRunning: boolean;
            sessionBound: boolean;
            ownership: {
              gatewayAuthority: string;
              sessionContinuity: string;
            };
            persistentHarness: {
              state: string;
            };
          };
          latestNativeToolSession: {
            handleId: string;
          } | null;
        };
      };
      expect(sessionBody.session.lifecycle.gatewayRunning).toBe(true);
      expect(sessionBody.session.lifecycle.sessionBound).toBe(true);
      expect(sessionBody.session.lifecycle.ownership.gatewayAuthority).toBe('service');
      expect(sessionBody.session.lifecycle.ownership.sessionContinuity).toBe('on_demand');
      expect(sessionBody.session.lifecycle.persistentHarness.state).toBe('n/a');
      expect(sessionBody.session.latestNativeToolSession?.handleId).toBe(firstRunBody.nativeToolSession?.handleId);
      expect(openRouterCalls).toBeGreaterThanOrEqual(2);
    } finally {
      if (installedSkill) {
        await inject({
          method: 'POST',
          url: '/api/skills/remove',
          headers: {
            Authorization: `Bearer ${config.server.apiToken}`
          },
          payload: {
            skillName: 'installed-skill',
            approved: true
          }
        });
      }

      await inject({
        method: 'PATCH',
        url: '/api/agents/profiles/ceo-default',
        headers: {
          Authorization: `Bearer ${config.server.apiToken}`
        },
        payload: {
          executionMode: previousExecutionMode
        }
      });

      vi.stubGlobal('fetch', originalFetch);
      if (originalOpenRouterKey === undefined) {
        delete process.env.OPENROUTER_API_KEY;
      } else {
        process.env.OPENROUTER_API_KEY = originalOpenRouterKey;
      }
    }
  }, 20_000);

  it('records native tool policy blocks when a tool-backed skill is blocked by server policy', async () => {
    const originalFetch = globalThis.fetch;
    const originalOpenRouterKey = process.env.OPENROUTER_API_KEY;
    process.env.OPENROUTER_API_KEY = 'integration-openrouter-key';

    const skillRoot = fs.mkdtempSync(path.join(os.tmpdir(), 'ops-native-tool-block-'));
    const skillDir = path.join(skillRoot, 'native-blocked-skill');
    fs.mkdirSync(skillDir, { recursive: true });
    fs.writeFileSync(
      path.join(skillDir, 'SKILL.md'),
      [
        '---',
        'name: native-blocked-skill',
        'description: native tool policy blocked skill',
        'requiredTools:',
        '  - git',
        '---',
        '# Native Blocked Skill',
        '',
        'This skill depends on the git tool.'
      ].join('\n')
    );

    let openRouterCalls = 0;
    const fetchMock = vi.fn(async (input: unknown) => {
      const url = String(input ?? '');
      if (!url.includes('openrouter.ai/api/v1/chat/completions')) {
        return new Response(JSON.stringify({ ok: true }), {
          status: 200,
          headers: { 'content-type': 'application/json' }
        });
      }
      openRouterCalls += 1;
      return new Response(
        JSON.stringify(
          openRouterCalls === 1
            ? {
                id: 'chatcmpl-native-skill-block-1',
                choices: [
                  {
                    message: {
                      content: '',
                      tool_calls: [
                        {
                          id: 'call_skill_block_1',
                          function: {
                            name: 'skill_call',
                            arguments: JSON.stringify({
                              skill: 'native-blocked-skill',
                              payload: {
                                smoke: true
                              },
                              reason: 'Need the blocked skill'
                            })
                          }
                        }
                      ]
                    }
                  }
                ]
              }
            : {
                id: 'chatcmpl-native-skill-block-2',
                choices: [
                  {
                    message: {
                      content: 'Final answer after blocked native skill attempt.'
                    }
                  }
                ]
              }
        ),
        {
          status: 200,
          headers: {
            'content-type': 'application/json'
          }
        }
      );
    });
    vi.stubGlobal('fetch', fetchMock as unknown as typeof fetch);

    let previousExecutionMode: 'on_demand' | 'persistent_harness' | 'dispatch_only' = 'on_demand';
    let gitWasDisabled = false;
    let catalogAdded = false;
    try {
      const profilesResponse = await inject({
        method: 'GET',
        url: '/api/agents/profiles'
      });
      expect(profilesResponse.statusCode).toBe(200);
      const profilesBody = profilesResponse.json() as {
        agents: Array<{ id: string; executionMode: 'on_demand' | 'persistent_harness' | 'dispatch_only' }>;
      };
      previousExecutionMode = profilesBody.agents.find((agent) => agent.id === 'ceo-default')?.executionMode ?? 'on_demand';

      const setOnDemand = await inject({
        method: 'PATCH',
        url: '/api/agents/profiles/ceo-default',
        headers: {
          Authorization: `Bearer ${config.server.apiToken}`
        },
        payload: {
          executionMode: 'on_demand'
        }
      });
      expect(setOnDemand.statusCode).toBe(200);

      const upserted = await inject({
        method: 'POST',
        url: '/api/skills/catalog/entries/upsert',
        headers: {
          Authorization: `Bearer ${config.server.apiToken}`
        },
        payload: {
          path: skillDir,
          approved: true
        }
      });
      expect(upserted.statusCode).toBe(200);
      catalogAdded = true;

      const disableGit = await inject({
        method: 'PATCH',
        url: '/api/tools/git',
        headers: {
          Authorization: `Bearer ${config.server.apiToken}`
        },
        payload: {
          enabled: false
        }
      });
      expect(disableGit.statusCode).toBe(200);
      gitWasDisabled = true;

      const created = await inject({
        method: 'POST',
        url: '/api/sessions',
        headers: {
          Authorization: `Bearer ${config.server.apiToken}`
        },
        payload: {
          label: 'ceo-native-tool-block-run',
          agentId: 'ceo-default',
          runtime: 'process',
          model: 'openrouter/free'
        }
      });
      expect(created.statusCode).toBe(201);
      const session = created.json() as { session: { id: string } };

      const queued = await inject({
        method: 'POST',
        url: `/api/sessions/${session.session.id}/runs`,
        headers: {
          Authorization: `Bearer ${config.server.apiToken}`,
          'Idempotency-Key': 'ceo-native-tool-block-run'
        },
        payload: {
          prompt: 'Use the native blocked skill for this smoke test.',
          runtime: 'process',
          model: 'openrouter/free',
          autoDelegate: false
        }
      });
      expect(queued.statusCode).toBe(201);
      const queuedBody = queued.json() as { run: { id: string } };

      const finalRun = await waitForTerminalRun(queuedBody.run.id);
      expect(finalRun.status).toBe('completed');

      const runResponse = await inject({
        method: 'GET',
        url: `/api/runs/${queuedBody.run.id}`
      });
      expect(runResponse.statusCode).toBe(200);
      const runBody = runResponse.json() as {
        run: { resultSummary: string | null };
        executionPath: {
          toolSessionMode: string | null;
        } | null;
      };
      expect(runBody.run.resultSummary).toContain('Final answer after blocked native skill attempt.');
      expect(runBody.executionPath?.toolSessionMode).toBe('native_tool_session');

      const timelineResponse = await inject({
        method: 'GET',
        url: `/api/runs/${queuedBody.run.id}/timeline`
      });
      expect(timelineResponse.statusCode).toBe(200);
      const timelineBody = timelineResponse.json() as {
        timeline: Array<{ type: string; payloadJson: string }>;
      };
      expect(timelineBody.timeline.some((entry) => entry.type === 'tool_call')).toBe(true);
      expect(timelineBody.timeline.some((entry) => entry.type === 'tool_policy_blocked')).toBe(true);
      const blockedEvent = timelineBody.timeline.find((entry) => entry.type === 'tool_policy_blocked');
      expect(String(blockedEvent?.payloadJson ?? '')).toContain('disabled by policy');
    } finally {
      if (gitWasDisabled) {
        await inject({
          method: 'PATCH',
          url: '/api/tools/git',
          headers: {
            Authorization: `Bearer ${config.server.apiToken}`
          },
          payload: {
            enabled: true
          }
        });
      }
      if (catalogAdded) {
        await inject({
          method: 'POST',
          url: '/api/skills/catalog/entries/remove',
          headers: {
            Authorization: `Bearer ${config.server.apiToken}`
          },
          payload: {
            path: skillDir,
            approved: true
          }
        });
      }
      await inject({
        method: 'PATCH',
        url: '/api/agents/profiles/ceo-default',
        headers: {
          Authorization: `Bearer ${config.server.apiToken}`
        },
        payload: {
          executionMode: previousExecutionMode
        }
      });
      vi.stubGlobal('fetch', originalFetch);
      if (originalOpenRouterKey === undefined) {
        delete process.env.OPENROUTER_API_KEY;
      } else {
        process.env.OPENROUTER_API_KEY = originalOpenRouterKey;
      }
      fs.rmSync(skillRoot, { recursive: true, force: true });
    }
  }, 20_000);

