  it('enforces llm limits, exposes cost APIs, and applies fallback routing', async () => {
    const unauthorizedUpdate = await inject({
      method: 'PUT',
      url: '/api/llm/limits',
      payload: {
        limits: {
          providerCallBudgetDaily: {
            openai: 1
          }
        }
      }
    });
    expect(unauthorizedUpdate.statusCode).toBe(401);

    const invalidUpdate = await inject({
      method: 'PUT',
      url: '/api/llm/limits',
      headers: {
        Authorization: `Bearer ${config.server.apiToken}`
      },
      payload: {
        limits: {
          providerCallBudgetDaily: {
            openai: -1
          }
        }
      }
    });
    expect(invalidUpdate.statusCode).toBe(400);

    const enableCodexRuntime = await inject({
      method: 'PATCH',
      url: '/api/tools/runtime%3Acodex',
      headers: {
        Authorization: `Bearer ${config.server.apiToken}`
      },
      payload: {
        enabled: true
      }
    });
    expect(enableCodexRuntime.statusCode).toBe(200);

    const updateLimits = await inject({
      method: 'PUT',
      url: '/api/llm/limits',
      headers: {
        Authorization: `Bearer ${config.server.apiToken}`
      },
      payload: {
        limits: {
          providerCallBudgetDaily: {
            openrouter: 0,
            google: 10000
          },
          providerCallsPerMinute: {},
          providerCostBudgetUsdDaily: {},
          providerCostBudgetUsdMonthly: {},
          modelCallBudgetDaily: {},
          fallbackByRuntime: {
            codex: [{ runtime: 'process', model: 'gemini-3-flash-preview' }],
            claude: [],
            gemini: [],
            process: []
          }
        }
      }
    });
    expect(updateLimits.statusCode).toBe(200);

    const limits = await inject({
      method: 'GET',
      url: '/api/llm/limits'
    });
    expect(limits.statusCode).toBe(200);
    const limitsBody = limits.json() as {
      limits: {
        providerCallBudgetDaily: Record<string, number>;
      };
    };
    expect(limitsBody.limits.providerCallBudgetDaily.openrouter).toBe(0);

    const sourceSession = await inject({
      method: 'POST',
      url: '/api/sessions',
      headers: {
        Authorization: `Bearer ${config.server.apiToken}`
      },
      payload: {
        label: 'llm-limits-fallback',
        agentId: 'software-engineer',
        runtime: 'process'
      }
    });
    expect(sourceSession.statusCode).toBe(201);
    const sourceBody = sourceSession.json() as { session: { id: string } };

    const fallbackRun = await inject({
      method: 'POST',
      url: `/api/sessions/${sourceBody.session.id}/runs`,
      headers: {
        Authorization: `Bearer ${config.server.apiToken}`,
        'Idempotency-Key': 'llm-fallback-1'
      },
      payload: {
        prompt: 'Use fallback route if needed',
        runtime: 'process'
      }
    });
    expect(fallbackRun.statusCode).toBe(201);
    const fallbackRunBody = fallbackRun.json() as { run: { id: string } };
    const fallbackRunStatus = await waitForTerminalRun(fallbackRunBody.run.id);
    expect(fallbackRunStatus.effectiveRuntime ?? fallbackRunStatus.runtime).toBe('process');
    expect((fallbackRunStatus.effectiveModel ?? fallbackRunStatus.model ?? '').toLowerCase()).toContain('gemini');
    expect(['completed', 'failed']).toContain(fallbackRunStatus.status);

    const tightenLimits = await inject({
      method: 'PUT',
      url: '/api/llm/limits',
      headers: {
        Authorization: `Bearer ${config.server.apiToken}`
      },
      payload: {
        limits: {
          providerCallBudgetDaily: {
            openrouter: 0,
            google: 0
          },
          providerCallsPerMinute: {},
          providerCostBudgetUsdDaily: {},
          providerCostBudgetUsdMonthly: {},
          modelCallBudgetDaily: {},
          fallbackByRuntime: {
            codex: [{ runtime: 'process', model: 'gemini-3-flash-preview' }],
            claude: [],
            gemini: [],
            process: []
          }
        }
      }
    });
    expect(tightenLimits.statusCode).toBe(200);

    const blockedRun = await inject({
      method: 'POST',
      url: `/api/sessions/${sourceBody.session.id}/runs`,
      headers: {
        Authorization: `Bearer ${config.server.apiToken}`,
        'Idempotency-Key': 'llm-blocked-1'
      },
      payload: {
        prompt: 'This should block on budget',
        runtime: 'process'
      }
    });
    expect(blockedRun.statusCode).toBe(201);
    const blockedRunBody = blockedRun.json() as { run: { id: string } };
    const blockedDeadline = Date.now() + 10_000;
    let blockedRunStatus: { status: string; error: string | null } | null = null;
    while (Date.now() < blockedDeadline) {
      const current = await inject({
        method: 'GET',
        url: `/api/runs/${blockedRunBody.run.id}`
      });
      expect(current.statusCode).toBe(200);
      const currentBody = current.json() as {
        run: {
          status: string;
          error: string | null;
        };
      };
      blockedRunStatus = currentBody.run;
      if (currentBody.run.status === 'waiting_input' || currentBody.run.status === 'failed') {
        break;
      }
      await new Promise((resolve) => setTimeout(resolve, 100));
    }
    expect(blockedRunStatus).toBeTruthy();
    expect(blockedRunStatus?.status).toBe('waiting_input');
    expect(blockedRunStatus?.error).toBe('budget_exhausted');
    const blockedOutbound = await waitForOutboundMessageByRun(sourceBody.session.id, blockedRunBody.run.id);
    expect(blockedOutbound.content).toContain('paused and is waiting for resume');
    expect(blockedOutbound.content).toContain('/resume in Telegram');

    const routing = await inject({
      method: 'GET',
      url: '/api/llm/routing/effective?runtime=process'
    });
    expect(routing.statusCode).toBe(200);
    const routingBody = routing.json() as {
      routes: Array<{ runtime: string; selected: { runtime: string } | null; reason: string }>;
    };
    expect(routingBody.routes[0]?.runtime).toBe('process');
    expect(routingBody.routes[0]?.selected).toBeNull();
    expect(routingBody.routes[0]?.reason).toBe('budget_exhausted');

    const costs = await inject({
      method: 'GET',
      url: '/api/llm/costs'
    });
    expect(costs.statusCode).toBe(200);
    const costsBody = costs.json() as {
      costs: {
        providerDaily: Array<{ provider: string; blocked: number }>;
      };
    };
    expect(costsBody.costs.providerDaily.some((row) => row.provider === 'google')).toBe(true);
    expect(costsBody.costs.providerDaily.some((row) => row.blocked > 0)).toBe(true);
  });

