  it('executes native OpenRouter execute_command tool sessions and answers with a follow-up LLM pass', async () => {
    const originalFetch = globalThis.fetch;
    const originalOpenRouterKey = process.env.OPENROUTER_API_KEY;
    process.env.OPENROUTER_API_KEY = 'integration-openrouter-key';

    const openRouterRequestBodies: Record<string, unknown>[] = [];
    const fetchMock = vi.fn(async (input: unknown, init?: RequestInit) => {
      const url = String(input ?? '');
      if (!url.includes('openrouter.ai/api/v1/chat/completions')) {
        return new Response(JSON.stringify({ ok: true }), {
          status: 200,
          headers: { 'content-type': 'application/json' }
        });
      }
      if (typeof init?.body === 'string') {
        const requestBody: Record<string, unknown> = JSON.parse(init.body);
        openRouterRequestBodies.push(requestBody);
      }
      if (openRouterRequestBodies.length === 1) {
        return new Response(
          JSON.stringify({
            id: 'chatcmpl-native-command-1',
            choices: [
              {
                message: {
                  content: '',
                  tool_calls: [
                    {
                      id: 'call_execute_1',
                      function: {
                        name: 'execute_command',
                        arguments: JSON.stringify({
                          command: 'pwd',
                          cwd: path.resolve(root),
                          reason: 'Need the workspace path before replying.'
                        })
                      }
                    }
                  ]
                }
              }
            ],
            usage: {
              prompt_tokens: 14,
              completion_tokens: 9,
              total_tokens: 23
            }
          }),
          {
            status: 200,
            headers: {
              'content-type': 'application/json'
            }
          }
        );
      }
      return new Response(
        JSON.stringify({
          id: 'chatcmpl-native-command-2',
          choices: [
            {
              message: {
                content: `The workspace path is ${path.resolve(root)}. \`pwd\` completed successfully.`
              }
            }
          ],
          usage: {
            prompt_tokens: 20,
            completion_tokens: 12,
            total_tokens: 32
          }
        }),
        {
          status: 200,
          headers: {
            'content-type': 'application/json'
          }
        }
      );
    });
    vi.stubGlobal('fetch', fetchMock as unknown as typeof fetch);

    let previousExecutionMode: 'on_demand' | 'persistent_harness' | 'dispatch_only' = 'on_demand';
    try {
      const profilesResponse = await inject({
        method: 'GET',
        url: '/api/agents/profiles'
      });
      expect(profilesResponse.statusCode).toBe(200);
      const profilesBody = profilesResponse.json() as {
        agents: Array<{ id: string; executionMode: 'on_demand' | 'persistent_harness' | 'dispatch_only' }>;
      };
      previousExecutionMode = profilesBody.agents.find((agent) => agent.id === 'ceo-default')?.executionMode ?? 'on_demand';

      const setOnDemand = await inject({
        method: 'PATCH',
        url: '/api/agents/profiles/ceo-default',
        headers: {
          Authorization: `Bearer ${config.server.apiToken}`
        },
        payload: {
          executionMode: 'on_demand'
        }
      });
      expect(setOnDemand.statusCode).toBe(200);

      const created = await inject({
        method: 'POST',
        url: '/api/sessions',
        headers: {
          Authorization: `Bearer ${config.server.apiToken}`
        },
        payload: {
          label: 'ceo-native-command-run',
          agentId: 'ceo-default',
          runtime: 'process',
          model: 'openrouter/free'
        }
      });
      expect(created.statusCode).toBe(201);
      const session = created.json() as { session: { id: string } };

      const queued = await inject({
        method: 'POST',
        url: `/api/sessions/${session.session.id}/runs`,
        headers: {
          Authorization: `Bearer ${config.server.apiToken}`,
          'Idempotency-Key': 'ceo-native-command-run'
        },
        payload: {
          prompt: 'Run `pwd` and summarize the result.',
          runtime: 'process',
          model: 'openrouter/free',
          autoDelegate: false
        }
      });
      expect(queued.statusCode).toBe(201);
      const queuedBody = queued.json() as { run: { id: string } };

      const finalRun = await waitForTerminalRun(queuedBody.run.id);
      expect(finalRun.status).toBe('completed');

      expect(openRouterRequestBodies).toHaveLength(2);
      expect(Array.isArray(openRouterRequestBodies[0]?.tools)).toBe(true);
      const nativeToolNames = Array.isArray(openRouterRequestBodies[0]?.tools)
        ? openRouterRequestBodies[0]!.tools
            .map((entry) =>
              typeof entry === 'object' && entry !== null && typeof (entry as { function?: { name?: string } }).function?.name === 'string'
                ? (entry as { function: { name: string } }).function.name
                : null
            )
            .filter((entry): entry is string => entry !== null)
        : [];
      expect(nativeToolNames).toContain('execute_command');
      expect(openRouterRequestBodies[1]?.tools).toBeUndefined();

      const runResponse = await inject({
        method: 'GET',
        url: `/api/runs/${queuedBody.run.id}`
      });
      expect(runResponse.statusCode).toBe(200);
      const runBody = runResponse.json() as {
        run: { resultSummary: string | null };
        executionPath: {
          mode: string;
          toolSessionMode: string | null;
          toolInvocationPath: string | null;
        } | null;
      };
      expect(runBody.run.resultSummary).toContain(`The workspace path is ${path.resolve(root)}.`);
      expect(runBody.run.resultSummary).not.toContain('Direct command result:');
      expect(runBody.executionPath?.mode).toBe('provider_api');
      expect(runBody.executionPath?.toolSessionMode).toBe('native_tool_session');
      expect(runBody.executionPath?.toolInvocationPath).toBe('tool_first_native');

      const timelineResponse = await inject({
        method: 'GET',
        url: `/api/runs/${queuedBody.run.id}/timeline`
      });
      expect(timelineResponse.statusCode).toBe(200);
      const timelineBody = timelineResponse.json() as {
        timeline: Array<{ type: string; payloadJson: string }>;
      };
      expect(timelineBody.timeline.some((entry) => entry.type === 'tool_call')).toBe(true);
      const toolCall = timelineBody.timeline.find((entry) => entry.type === 'tool_call');
      expect(JSON.parse(String(toolCall?.payloadJson ?? '{}')).toolName).toBe('execute_command');
      const replyPath = timelineBody.timeline.find((entry) => entry.type === 'run.reply_path');
      expect(JSON.parse(String(replyPath?.payloadJson ?? '{}')).mode).toBe('llm_followup');

      const outbound = await waitForOutboundMessageByRun(session.session.id, queuedBody.run.id, 10_000);
      expect(outbound.content).toContain(`The workspace path is ${path.resolve(root)}.`);
      expect(outbound.content).not.toContain('Direct command result:');
    } finally {
      const resetProfile = await inject({
        method: 'PATCH',
        url: '/api/agents/profiles/ceo-default',
        headers: {
          Authorization: `Bearer ${config.server.apiToken}`
        },
        payload: {
          executionMode: previousExecutionMode
        }
      });
      expect(resetProfile.statusCode).toBe(200);
      vi.stubGlobal('fetch', originalFetch);
      if (originalOpenRouterKey === undefined) {
        delete process.env.OPENROUTER_API_KEY;
      } else {
        process.env.OPENROUTER_API_KEY = originalOpenRouterKey;
      }
    }
  });

