  it('persists agent memory action contracts from run output and strips contract payloads from outbound messages', async () => {
    const previousFetch = globalThis.fetch;
    const contractBlock = JSON.stringify({
      schema: 'ops.memory-actions.v1',
      type: 'memory_actions',
      version: 1,
      actions: [
        {
          action: 'remember',
          content: 'Store this preference for release workflows.',
          tags: ['release', 'preference'],
          reason: 'user asked to remember release workflow preference'
        }
      ]
    });
    const fetchMock = vi.fn(async (input: URL | RequestInfo) => {
      const url =
        typeof input === 'string'
          ? input
          : input instanceof URL
            ? input.toString()
            : typeof input === 'object' && input !== null && 'url' in input
              ? String((input as { url?: unknown }).url ?? '')
              : '';
      if (url.includes('generativelanguage.googleapis.com')) {
        const geminiPayload = {
          candidates: [
            {
              content: {
                parts: [
                  {
                    text: ['Acknowledged. Persisting the preference.', '```json', contractBlock, '```'].join('\n')
                  }
                ]
              }
            }
          ],
          usageMetadata: {
            promptTokenCount: 28,
            candidatesTokenCount: 22,
            totalTokenCount: 50
          }
        };
        return new Response(JSON.stringify(geminiPayload), {
          status: 200,
          headers: {
            'Content-Type': 'application/json'
          }
        });
      }

      const openRouterPayload = {
        id: 'chatcmpl-memory-directive',
        choices: [
          {
            message: {
              content: ['Acknowledged. Persisting the preference.', '```json', contractBlock, '```'].join('\n')
            }
          }
        ],
        usage: {
          prompt_tokens: 32,
          completion_tokens: 24,
          total_tokens: 56
        }
      };
      return new Response(JSON.stringify(openRouterPayload), {
        status: 200,
        headers: {
          'Content-Type': 'application/json'
        }
      });
    });
    vi.stubGlobal('fetch', fetchMock as unknown as typeof fetch);

    try {
      const created = await inject({
        method: 'POST',
        url: '/api/sessions',
        headers: {
          Authorization: `Bearer ${config.server.apiToken}`
        },
        payload: {
          label: 'memory-directive-session',
          agentId: 'software-engineer',
          runtime: 'process',
          model: 'default'
        }
      });
      expect(created.statusCode).toBe(201);
      const createdBody = created.json() as {
        session: {
          id: string;
          agentId: string;
        };
      };

      const runResponse = await inject({
        method: 'POST',
        url: `/api/sessions/${createdBody.session.id}/runs`,
        headers: {
          Authorization: `Bearer ${config.server.apiToken}`,
          'Idempotency-Key': 'memory-directive-run'
        },
        payload: {
          runtime: 'process',
          prompt: 'User says: remember our release workflow preference.'
        }
      });
      expect(runResponse.statusCode).toBe(201);
      const runBody = runResponse.json() as { run: { id: string } };
      const terminal = await waitForTerminalRun(runBody.run.id, 20_000);
      expect(terminal.status).toBe('completed');

      const outbound = await waitForOutboundMessageByRun(createdBody.session.id, runBody.run.id, 15_000);
      expect(outbound.content.includes('ops.memory-actions.v1')).toBe(false);
      expect(outbound.content.includes('memory_actions')).toBe(false);

      const sessionResponse = await inject({
        method: 'GET',
        url: `/api/sessions/${createdBody.session.id}`
      });
      expect(sessionResponse.statusCode).toBe(200);
      const sessionBody = sessionResponse.json() as { session: { agentId: string } };

      const memorySearch = await inject({
        method: 'GET',
        url: `/api/memory/search?agentId=${encodeURIComponent(sessionBody.session.agentId)}&query=${encodeURIComponent('release workflows')}&limit=5`
      });
      expect(memorySearch.statusCode).toBe(200);
      const memorySearchBody = memorySearch.json() as {
        results: Array<{
          item: {
            content: string;
          };
        }>;
      };
      const persistedDirective = memorySearchBody.results.find((entry) =>
        entry.item.content.includes('Store this preference for release workflows.')
      );
      expect(Boolean(persistedDirective)).toBe(true);
    } finally {
      vi.stubGlobal('fetch', previousFetch as unknown as typeof fetch);
    }
  });

  it('repairs native OpenRouter execute_command usage failures with a deterministic help probe before the corrected retry', async () => {
    const originalFetch = globalThis.fetch;
    const originalOpenRouterKey = process.env.OPENROUTER_API_KEY;
    process.env.OPENROUTER_API_KEY = 'integration-openrouter-key';
    const queryToolPath = path.join(root, 'querytool-repair-openrouter');
    fs.writeFileSync(
      queryToolPath,
      [
        '#!/usr/bin/env bash',
        'set -euo pipefail',
        'if [ "${1:-}" != "search" ]; then',
        '  echo "Usage: querytool-repair-openrouter search [OPTIONS] QUERY" >&2',
        '  exit 2',
        'fi',
        'shift',
        'if [ "${1:-}" = "--help" ]; then',
        '  echo "Usage: querytool-repair-openrouter search [OPTIONS] QUERY"',
        '  exit 0',
        'fi',
        'if [ "${1:-}" = "--definitely-not-a-real-flag" ]; then',
        '  echo "Usage: querytool-repair-openrouter search [OPTIONS] QUERY" >&2',
        '  echo "Error: No such option: --definitely-not-a-real-flag" >&2',
        '  exit 2',
        'fi',
        'printf \"%s\\n\" \"$*\"'
      ].join('\n'),
      { mode: 0o755 }
    );

    const openRouterRequestBodies: Record<string, unknown>[] = [];
    const fetchMock = vi.fn(async (input: unknown, init?: RequestInit) => {
      const url = String(input ?? '');
      if (!url.includes('openrouter.ai/api/v1/chat/completions')) {
        return new Response(JSON.stringify({ ok: true }), {
          status: 200,
          headers: { 'content-type': 'application/json' }
        });
      }
      if (typeof init?.body === 'string') {
        openRouterRequestBodies.push(JSON.parse(init.body) as Record<string, unknown>);
      }
      if (openRouterRequestBodies.length === 1) {
        return new Response(
          JSON.stringify({
            id: 'chatcmpl-native-command-repair-1',
            choices: [
              {
                message: {
                  content: '',
                  tool_calls: [
                    {
                      id: 'call_execute_repair_1',
                      function: {
                        name: 'execute_command',
                        arguments: JSON.stringify({
                          command: './querytool-repair-openrouter search --definitely-not-a-real-flag',
                          cwd: path.resolve(root),
                          reason: 'Repair a CLI usage failure before answering.'
                        })
                      }
                    }
                  ]
                }
              }
            ],
            usage: {
              prompt_tokens: 18,
              completion_tokens: 10,
              total_tokens: 28
            }
          }),
          {
            status: 200,
            headers: {
              'content-type': 'application/json'
            }
          }
        );
      }
      if (openRouterRequestBodies.length === 2) {
        return new Response(
          JSON.stringify({
            id: 'chatcmpl-native-command-repair-2',
            choices: [
              {
                message: {
                  content: '',
                  tool_calls: [
                    {
                      id: 'call_execute_repair_2',
                      function: {
                        name: 'execute_command',
                        arguments: JSON.stringify({
                          argv: ['./querytool-repair-openrouter', 'search', 'repair ok from openrouter'],
                          cwd: path.resolve(root),
                          reason: 'Retry with a valid query tool command.'
                        })
                      }
                    }
                  ]
                }
              }
            ],
            usage: {
              prompt_tokens: 26,
              completion_tokens: 12,
              total_tokens: 38
            }
          }),
          {
            status: 200,
            headers: {
              'content-type': 'application/json'
            }
          }
        );
      }
      return new Response(
        JSON.stringify({
          id: 'chatcmpl-native-command-repair-3',
          choices: [
            {
              message: {
                content: 'The query tool worked. The repaired command printed `repair ok from openrouter`.'
              }
            }
          ],
          usage: {
            prompt_tokens: 22,
            completion_tokens: 11,
            total_tokens: 33
          }
        }),
        {
          status: 200,
          headers: {
            'content-type': 'application/json'
          }
        }
      );
    });
    vi.stubGlobal('fetch', fetchMock as unknown as typeof fetch);

    let previousExecutionMode: 'on_demand' | 'persistent_harness' | 'dispatch_only' = 'on_demand';
    try {
      const profilesResponse = await inject({
        method: 'GET',
        url: '/api/agents/profiles'
      });
      expect(profilesResponse.statusCode).toBe(200);
      const profilesBody = profilesResponse.json() as {
        agents: Array<{ id: string; executionMode: 'on_demand' | 'persistent_harness' | 'dispatch_only' }>;
      };
      previousExecutionMode = profilesBody.agents.find((agent) => agent.id === 'ceo-default')?.executionMode ?? 'on_demand';

      const setOnDemand = await inject({
        method: 'PATCH',
        url: '/api/agents/profiles/ceo-default',
        headers: {
          Authorization: `Bearer ${config.server.apiToken}`
        },
        payload: {
          executionMode: 'on_demand'
        }
      });
      expect(setOnDemand.statusCode).toBe(200);

      const created = await inject({
        method: 'POST',
        url: '/api/sessions',
        headers: {
          Authorization: `Bearer ${config.server.apiToken}`
        },
        payload: {
          label: 'ceo-native-command-repair-openrouter',
          agentId: 'ceo-default',
          runtime: 'process',
          model: 'openrouter/free'
        }
      });
      expect(created.statusCode).toBe(201);
      const session = created.json() as { session: { id: string } };

      const queued = await inject({
        method: 'POST',
        url: `/api/sessions/${session.session.id}/runs`,
        headers: {
          Authorization: `Bearer ${config.server.apiToken}`,
          'Idempotency-Key': 'ceo-native-command-repair-openrouter'
        },
        payload: {
          prompt: 'Run the query tool and tell me whether the repair succeeded.',
          runtime: 'process',
          model: 'openrouter/free',
          autoDelegate: false
        }
      });
      expect(queued.statusCode).toBe(201);
      const queuedBody = queued.json() as { run: { id: string } };

      const finalRun = await waitForRunStatus(queuedBody.run.id, 'completed');
      expect(finalRun.status).toBe('completed');
      expect(openRouterRequestBodies.length).toBeGreaterThanOrEqual(1);
      expect(openRouterRequestBodies[0]?.tools).toBeTruthy();

      const outbound = await waitForOutboundMessageByRun(session.session.id, queuedBody.run.id, 10_000);
      expect(outbound.content).toContain('repair ok from openrouter');
      expect(outbound.content).not.toContain('Direct command result:');
      expect(outbound.content).not.toContain('--definitely-not-a-real-flag');
      expect(outbound.content.toLowerCase()).not.toContain('failed initially');

      const timelineResponse = await inject({
        method: 'GET',
        url: `/api/runs/${queuedBody.run.id}/timeline`
      });
      expect(timelineResponse.statusCode).toBe(200);
      const timelineBody = timelineResponse.json() as {
        timeline: Array<{ type: string; payloadJson: string }>;
      };
      const toolCalls = timelineBody.timeline.filter((entry) => entry.type === 'tool_call');
      expect(toolCalls.length).toBeGreaterThanOrEqual(1);
      const repairEvents = timelineBody.timeline.filter((entry) => entry.type === 'run.direct_command_repair');
      expect(repairEvents.length).toBeGreaterThanOrEqual(1);
      const repairPayloads = repairEvents.map((entry) => String(entry.payloadJson ?? ''));
      expect(repairPayloads.some((payload) => payload.includes('help_probe_completed'))).toBe(true);
      expect(repairPayloads.some((payload) => payload.includes('repair_command_completed'))).toBe(true);
      expect(repairPayloads.some((payload) => payload.includes('querytool-repair-openrouter'))).toBe(true);
      const replyPath = timelineBody.timeline.find((entry) => entry.type === 'run.reply_path');
      expect(['llm_followup', 'evidence_fallback']).toContain(
        JSON.parse(String(replyPath?.payloadJson ?? '{}')).mode
      );
    } finally {
      const resetProfile = await inject({
        method: 'PATCH',
        url: '/api/agents/profiles/ceo-default',
        headers: {
          Authorization: `Bearer ${config.server.apiToken}`
        },
        payload: {
          executionMode: previousExecutionMode
        }
      });
      expect(resetProfile.statusCode).toBe(200);
      vi.stubGlobal('fetch', originalFetch);
      if (originalOpenRouterKey === undefined) {
        delete process.env.OPENROUTER_API_KEY;
      } else {
        process.env.OPENROUTER_API_KEY = originalOpenRouterKey;
      }
      fs.rmSync(queryToolPath, { force: true });
    }
  });

