  it('falls back backlog batch assignment routing when primary provider returns saturation', async () => {
    const originalFetch = globalThis.fetch;
    const previousOpenRouterApiKey = process.env.OPENROUTER_API_KEY;
    const previousGoogleApiKey = process.env.GOOGLE_API_KEY;
    process.env.OPENROUTER_API_KEY = 'openrouter-test-key-for-routing';
    process.env.GOOGLE_API_KEY = 'google-test-key-for-routing';

    let plannedItemId = '';
    const fetchMock = vi.fn(async (input: URL | RequestInfo) => {
      const url = typeof input === 'string' ? input : input instanceof URL ? input.toString() : input.url;
      if (url.includes('generativelanguage.googleapis.com')) {
        return new Response(
          JSON.stringify({
            error: {
              message: '503 service unavailable: provider saturation'
            }
          }),
          {
            status: 503,
            headers: {
              'content-type': 'application/json'
            }
          }
        );
      }
      if (url.includes('openrouter.ai/api/v1/chat/completions')) {
        return new Response(
          JSON.stringify({
            choices: [
              {
                message: {
                  content: JSON.stringify({
                    assignments: [
                      {
                        itemId: plannedItemId,
                        targetAgentId: 'software-engineer',
                        reason: 'fallback model selected best delegate',
                        confidence: 0.89,
                        rankedAgentIds: ['software-engineer']
                      }
                    ],
                    reason: 'batch fallback assignment succeeded'
                  })
                }
              }
            ],
            usage: {
              prompt_tokens: 132,
              completion_tokens: 31,
              total_tokens: 163
            }
          }),
          {
            status: 200,
            headers: {
              'content-type': 'application/json'
            }
          }
        );
      }
      throw new Error(`Unexpected fetch url: ${url}`);
    });
    vi.stubGlobal('fetch', fetchMock as unknown as typeof fetch);

    const limitsUpdate = await inject({
      method: 'PUT',
      url: '/api/llm/limits',
      headers: {
        Authorization: `Bearer ${config.server.apiToken}`
      },
      payload: {
        limits: {
          orchestratorPrimaryModelByRuntime: {
            process: 'gemini-3.1-pro-preview'
          },
          orchestratorFallbackByRuntime: {
            process: [{ runtime: 'process', model: 'openrouter/openai/gpt-5-mini' }]
          }
        }
      }
    });
    expect(limitsUpdate.statusCode).toBe(200);

    const enableOrchestration = await inject({
      method: 'PUT',
      url: '/api/backlog/orchestration',
      headers: {
        Authorization: `Bearer ${config.server.apiToken}`
      },
      payload: {
        enabled: true,
        paused: false,
        maxParallel: 12,
        wipLimit: 12
      }
    });
    expect(enableOrchestration.statusCode).toBe(200);

    try {
      const createItem = await inject({
        method: 'POST',
        url: '/api/backlog/items',
        headers: {
          Authorization: `Bearer ${config.server.apiToken}`
        },
        payload: {
          title: 'Fallback router assignment item',
          description: 'Needs delegated implementation via fallback route.',
          state: 'planned',
          priority: 99,
          actor: 'test'
        }
      });
      expect(createItem.statusCode).toBe(201);
      const createItemBody = createItem.json() as { item: { id: string } };
      plannedItemId = createItemBody.item.id;

      const tick = await inject({
        method: 'POST',
        url: '/api/backlog/orchestration/tick',
        headers: {
          Authorization: `Bearer ${config.server.apiToken}`
        },
        payload: {
          actor: 'test'
        }
      });
      expect(tick.statusCode).toBe(200);
      const tickBody = tick.json() as {
        dispatched: Array<{ itemId: string; targetAgentId: string }>;
      };
      expect(
        tickBody.dispatched.some((entry) => entry.itemId === plannedItemId && entry.targetAgentId === 'software-engineer')
      ).toBe(true);

      const calledUrls = fetchMock.mock.calls.map(([input]) =>
        typeof input === 'string' ? input : input instanceof URL ? input.toString() : input.url
      );
      expect(calledUrls.some((url) => url.includes('generativelanguage.googleapis.com'))).toBe(true);
      expect(calledUrls.some((url) => url.includes('openrouter.ai/api/v1/chat/completions'))).toBe(true);
    } finally {
      await inject({
        method: 'PUT',
        url: '/api/llm/limits',
        headers: {
          Authorization: `Bearer ${config.server.apiToken}`
        },
        payload: {
          limits: {}
        }
      });
      vi.stubGlobal('fetch', originalFetch);
      if (previousOpenRouterApiKey === undefined) {
        delete process.env.OPENROUTER_API_KEY;
      } else {
        process.env.OPENROUTER_API_KEY = previousOpenRouterApiKey;
      }
      if (previousGoogleApiKey === undefined) {
        delete process.env.GOOGLE_API_KEY;
      } else {
        process.env.GOOGLE_API_KEY = previousGoogleApiKey;
      }
    }
  });

  it('bridges delegated backlog completion receipts to the origin linked session', async () => {
    const ingress = await inject({
      method: 'POST',
      url: '/api/ingress/telegram',
      payload: {
        update_id: 41001,
        message: {
          text: 'track delegated backlog delivery',
          chat: { id: 41001, type: 'private' },
          from: { id: 41001, username: 'backlog-owner' },
          mentioned: true
        }
      }
    });
    expect(ingress.statusCode).toBe(200);
    const ingressBody = ingress.json() as {
      sessionId: string;
    };

    const createItem = await inject({
      method: 'POST',
      url: '/api/backlog/items',
      headers: {
        Authorization: `Bearer ${config.server.apiToken}`
      },
      payload: {
        title: 'Delegated backlog receipt test',
        description: 'Run and report back to the requester session.',
        state: 'planned',
        priority: 96,
        actor: 'test',
        linkedSessionId: ingressBody.sessionId
      }
    });
    expect(createItem.statusCode).toBe(201);
    const createItemBody = createItem.json() as { item: { id: string } };

    const forceDelegate = await inject({
      method: 'POST',
      url: '/api/backlog/orchestration/override',
      headers: {
        Authorization: `Bearer ${config.server.apiToken}`
      },
      payload: {
        itemId: createItemBody.item.id,
        action: 'force_delegate',
        actor: 'test',
        reason: 'verify delegated delivery receipt flow',
        targetAgentId: 'software-engineer'
      }
    });
    expect(forceDelegate.statusCode).toBe(200);
    const forceDelegateBody = forceDelegate.json() as {
      delegation: { runId: string; targetSessionId: string };
    };

    const delegatedRun = await waitForTerminalRun(forceDelegateBody.delegation.runId);
    expect(['completed', 'failed', 'aborted']).toContain(delegatedRun.status);

    const receiptDeadline = Date.now() + 10_000;
    let receipt:
      | {
          direction: string;
          content: string;
          metadataJson: string;
        }
      | null = null;
    while (Date.now() < receiptDeadline) {
      const response = await inject({
        method: 'GET',
        url: `/api/messages?sessionId=${encodeURIComponent(ingressBody.sessionId)}`
      });
      expect(response.statusCode).toBe(200);
      const body = response.json() as {
        messages: Array<{ direction: string; content: string; metadataJson: string }>;
      };
      receipt =
        body.messages
          .filter((entry) => entry.direction === 'outbound')
          .find((entry) => {
            const metadata = JSON.parse(entry.metadataJson) as { command?: string; delegatedRunId?: string };
            return metadata.command === 'backlog_receipt' && metadata.delegatedRunId === forceDelegateBody.delegation.runId;
          }) ?? null;
      if (receipt) {
        break;
      }
      await new Promise((resolve) => setTimeout(resolve, 100));
    }
    expect(receipt).toBeTruthy();
    const receiptMetadata = JSON.parse(receipt!.metadataJson) as {
      status?: string;
      backlogItemId?: string;
      delegatedReceiptKey?: string;
    };
    expect(receiptMetadata.status).toBe(delegatedRun.status);
    expect(receiptMetadata.backlogItemId).toBe(createItemBody.item.id);
    expect(receiptMetadata.delegatedReceiptKey).toBe(`backlog:${forceDelegateBody.delegation.runId}:${delegatedRun.status}`);
    expect(receipt!.content).toContain('Backlog update: Delegated backlog receipt test');
    expect(receipt!.content).not.toMatch(/currently operating on/i);
    expect(receipt!.content).not.toMatch(/requested model was/i);

    const lifecycleDeadline = Date.now() + 10_000;
    let lifecycleStages = new Set<string>();
    while (Date.now() < lifecycleDeadline) {
      const response = await inject({
        method: 'GET',
        url: `/api/messages?sessionId=${encodeURIComponent(ingressBody.sessionId)}`
      });
      expect(response.statusCode).toBe(200);
      const body = response.json() as {
        messages: Array<{ direction: string; metadataJson: string }>;
      };
      lifecycleStages = new Set(
        body.messages
          .filter((entry) => entry.direction === 'outbound')
          .map((entry) => JSON.parse(entry.metadataJson) as { command?: string; stage?: string; delegatedRunId?: string })
          .filter((metadata) => metadata.command === 'backlog_lifecycle' && metadata.delegatedRunId === forceDelegateBody.delegation.runId)
          .map((metadata) => metadata.stage ?? '')
          .filter((stage) => stage.length > 0)
      );
      if (lifecycleStages.has('queued') && lifecycleStages.has('accepted') && lifecycleStages.has('running')) {
        break;
      }
      await new Promise((resolve) => setTimeout(resolve, 100));
    }
    expect(lifecycleStages.has('queued')).toBe(true);
    expect(lifecycleStages.has('accepted')).toBe(true);
    expect(lifecycleStages.has('running')).toBe(true);

    const itemDetails = await inject({
      method: 'GET',
      url: `/api/backlog/items/${createItemBody.item.id}`,
      headers: {
        Authorization: `Bearer ${config.server.apiToken}`
      }
    });
    expect(itemDetails.statusCode).toBe(200);
    const itemDetailsBody = itemDetails.json() as {
      item: {
        state: string;
        delivery: null | {
          status: string;
          metadata: {
            latestDelegatedRun?: {
              runId?: string;
              delegatedSessionId?: string;
              finalStatus?: string;
            };
            artifacts?: {
              workspaceRoot?: string;
              workspacePath?: string | null;
            };
          };
        };
      };
    };
    expect(itemDetailsBody.item.delivery).toBeTruthy();
    expect(itemDetailsBody.item.delivery!.status).toBe(delegatedRun.status === 'completed' ? 'review' : 'blocked');
    expect(itemDetailsBody.item.delivery!.metadata.latestDelegatedRun?.runId).toBe(forceDelegateBody.delegation.runId);
    expect(itemDetailsBody.item.delivery!.metadata.latestDelegatedRun?.delegatedSessionId).toBe(
      forceDelegateBody.delegation.targetSessionId
    );
    expect(itemDetailsBody.item.delivery!.metadata.latestDelegatedRun?.finalStatus).toBe(delegatedRun.status);
    expect(itemDetailsBody.item.delivery!.metadata.artifacts?.workspaceRoot).toBe(path.resolve(root));
    expect(typeof itemDetailsBody.item.delivery!.metadata.artifacts?.workspacePath).toBe('string');

    const requeue = await inject({
      method: 'POST',
      url: '/api/backlog/orchestration/override',
      headers: {
        Authorization: `Bearer ${config.server.apiToken}`
      },
      payload: {
        itemId: createItemBody.item.id,
        action: 'requeue',
        actor: 'test',
        reason: 'verify follow-up delegated notifications keep original Telegram session target'
      }
    });
    expect([200, 409]).toContain(requeue.statusCode);

    const forceDelegateAgain = await inject({
      method: 'POST',
      url: '/api/backlog/orchestration/override',
      headers: {
        Authorization: `Bearer ${config.server.apiToken}`
      },
      payload: {
        itemId: createItemBody.item.id,
        action: 'force_delegate',
        actor: 'test',
        reason: 'verify follow-up delegated delivery receipt flow',
        targetAgentId: 'software-engineer'
      }
    });
    expect(forceDelegateAgain.statusCode).toBe(200);
    const forceDelegateAgainBody = forceDelegateAgain.json() as {
      delegation: { runId: string; targetSessionId: string };
    };

    const secondDelegatedRun = await waitForTerminalRun(forceDelegateAgainBody.delegation.runId);
    expect(['completed', 'failed', 'aborted']).toContain(secondDelegatedRun.status);

    const secondReceiptDeadline = Date.now() + 10_000;
    let secondReceipt:
      | {
          direction: string;
          metadataJson: string;
        }
      | null = null;
    while (Date.now() < secondReceiptDeadline) {
      const response = await inject({
        method: 'GET',
        url: `/api/messages?sessionId=${encodeURIComponent(ingressBody.sessionId)}`
      });
      expect(response.statusCode).toBe(200);
      const body = response.json() as {
        messages: Array<{ direction: string; metadataJson: string }>;
      };
      secondReceipt =
        body.messages
          .filter((entry) => entry.direction === 'outbound')
          .find((entry) => {
            const metadata = JSON.parse(entry.metadataJson) as { command?: string; delegatedRunId?: string };
            return metadata.command === 'backlog_receipt' && metadata.delegatedRunId === forceDelegateAgainBody.delegation.runId;
          }) ?? null;
      if (secondReceipt) {
        break;
      }
      await new Promise((resolve) => setTimeout(resolve, 100));
    }
    expect(secondReceipt).toBeTruthy();
  }, 15_000);

