  it('derives privileged audit actors from request auth instead of trusting body.actor', async () => {
    const runtimeConfig = await inject({
      method: 'GET',
      url: '/api/config/runtime',
      headers: {
        Authorization: `Bearer ${config.server.apiToken}`
      }
    });
    expect(runtimeConfig.statusCode).toBe(200);
    const runtimeConfigBody = runtimeConfig.json() as {
      config: Record<string, unknown>;
    };

    const saveRuntimeConfig = await inject({
      method: 'PUT',
      url: '/api/config/runtime',
      headers: {
        Authorization: `Bearer ${config.server.apiToken}`,
        'x-ops-role': 'operator'
      },
      payload: {
        config: runtimeConfigBody.config,
        actor: 'spoofed-dashboard-actor'
      }
    });
    expect(saveRuntimeConfig.statusCode).toBe(200);

    const uniqueAction = `spoof-audit-check-${Date.now()}`;
    const elevatedCheck = await inject({
      method: 'POST',
      url: '/api/security/elevated-check',
      headers: {
        Authorization: `Bearer ${config.server.apiToken}`,
        'x-ops-role': 'operator'
      },
      payload: {
        requested: true,
        approved: false,
        action: uniqueAction,
        actor: 'spoofed-security-actor'
      }
    });
    expect([403, 412]).toContain(elevatedCheck.statusCode);

    const auditResponse = await inject({
      method: 'GET',
      url: '/api/audit',
      headers: {
        Authorization: `Bearer ${config.server.apiToken}`
      }
    });
    expect(auditResponse.statusCode).toBe(200);
    const auditBody = auditResponse.json() as {
      audit: Array<{ action: string; actor: string }>;
    };

    const configAudit = auditBody.audit.find((entry) => entry.action === 'config.runtime.update');
    expect(configAudit).toBeTruthy();
    expect(configAudit?.actor).toBe('api:operator');
    expect(configAudit?.actor).not.toBe('spoofed-dashboard-actor');

    const elevatedAudit = auditBody.audit.find((entry) => entry.action === uniqueAction);
    expect(elevatedAudit).toBeTruthy();
    expect(elevatedAudit?.actor).toBe('api:operator');
    expect(elevatedAudit?.actor).not.toBe('spoofed-security-actor');
  });

