  it('anchors manual CEO runs to sibling linked repos and remembers that workspace for follow-up runs', async () => {
    const customRoot = fs.mkdtempSync(path.join(os.tmpdir(), 'ops-linked-repo-runs-'));
    const customConfig = structuredClone(config) as any;
    customConfig.server.port = 8794;
    customConfig.runtime.workspaceRoot = path.join(customRoot, '.ops', 'workspaces');
    customConfig.persistence.sqlitePath = path.join(customRoot, 'state.db');
    fs.mkdirSync(customConfig.runtime.workspaceRoot, { recursive: true });

    const customApp = await buildGatewayApp(customConfig, {
      skillInstallRunner
    });
    const customInject = (options: Parameters<typeof customApp.inject>[0]) =>
      customApp.inject(
        typeof options === 'string'
          ? options
          : {
              ...options,
              headers: {
                Authorization: `Bearer ${customConfig.server.apiToken}`,
                'x-ops-role': 'operator',
                ...(options.headers ?? {})
              }
            }
      );
    const waitForCustomRun = async (runId: string, timeoutMs = 10_000): Promise<void> => {
      const deadline = Date.now() + timeoutMs;
      while (Date.now() < deadline) {
        const response = await customInject({
          method: 'GET',
          url: `/api/runs/${runId}`
        });
        expect(response.statusCode).toBe(200);
        const body = response.json() as {
          run: {
            status: string;
          };
        };
        if (['completed', 'failed', 'aborted'].includes(body.run.status)) {
          return;
        }
        await new Promise((resolve) => setTimeout(resolve, 100));
      }
      throw new Error(`Run ${runId} did not reach terminal status within ${timeoutMs}ms`);
    };

    try {
      const repoRoot = path.join(customRoot, '.ops', 'simulation-workspaces', 'ugothere.ai');
      fs.mkdirSync(repoRoot, { recursive: true });
      const runGit = (cwd: string, args: string[]): void => {
        const result = spawnSync('git', ['-C', cwd, ...args], {
          encoding: 'utf8'
        });
        expect(result.status).toBe(0);
      };
      runGit(repoRoot, ['init', '--initial-branch=main']);
      runGit(repoRoot, ['config', 'user.name', 'Gateway Integration']);
      runGit(repoRoot, ['config', 'user.email', 'gateway-integration@elyzelabs.local']);
      fs.writeFileSync(path.join(repoRoot, 'README.md'), '# ugothere.ai\n');
      runGit(repoRoot, ['add', 'README.md']);
      runGit(repoRoot, ['commit', '-m', 'init']);
      runGit(repoRoot, ['remote', 'add', 'origin', 'https://github.com/ElyzeSolutions/ugothere.ai.git']);
      const realRepoRoot = fs.realpathSync(repoRoot);

      const customDb = new ControlPlaneDatabase(customConfig.persistence.sqlitePath);
      customDb.upsertAgentProfile({
        id: 'ceo-default',
        name: 'CEO',
        title: 'Chief Executive Officer',
        systemPrompt: 'Coordinate repository work.',
        defaultRuntime: 'process',
        allowedRuntimes: ['process', 'codex', 'claude', 'gemini'],
        tools: ['runtime:process'],
        metadata: {
          executionMode: 'on_demand'
        },
        enabled: true
      });
      const session = customDb.upsertSessionByKey({
        sessionKey: 'linked-repo-manual-memory',
        channel: 'internal',
        chatType: 'internal',
        agentId: 'ceo-default',
        preferredRuntime: 'process'
      });
      const sessionId = session.id;
      const sessionWorkspace = path.join(customConfig.runtime.workspaceRoot, sessionId);

      const firstRun = await customInject({
        method: 'POST',
        url: `/api/sessions/${sessionId}/runs`,
        headers: {
          'Idempotency-Key': 'linked-repo-manual-run-1'
        },
        payload: {
          prompt: 'Clone ugothere.ai and add a contact page',
          runtime: 'process',
          autoDelegate: false
        }
      });
      expect(firstRun.statusCode).toBe(201);
      const firstRunBody = firstRun.json() as {
        run: {
          id: string;
        };
      };
      await waitForCustomRun(firstRunBody.run.id);

      const firstTerminal = await customInject({
        method: 'GET',
        url: `/api/runs/${firstRunBody.run.id}/terminal`
      });
      expect(firstTerminal.statusCode).toBe(200);
      const firstTerminalBody = firstTerminal.json() as {
        terminal: {
          workspacePath: string | null;
        } | null;
      };
      expect(firstTerminalBody.terminal?.workspacePath).toBe(realRepoRoot);
      expect(firstTerminalBody.terminal?.workspacePath).not.toBe(sessionWorkspace);

      const storedSession = customDb.getSessionById(sessionId);
      const storedMetadata = JSON.parse(String(storedSession?.metadataJson ?? '{}')) as {
        linkedRepoRoot?: string | null;
      };
      expect(storedMetadata.linkedRepoRoot).toBe(realRepoRoot);

      const secondRun = await customInject({
        method: 'POST',
        url: `/api/sessions/${sessionId}/runs`,
        headers: {
          'Idempotency-Key': 'linked-repo-manual-run-2'
        },
        payload: {
          prompt: 'Keep going and verify the navigation flow.',
          runtime: 'process',
          autoDelegate: false
        }
      });
      expect(secondRun.statusCode).toBe(201);
      const secondRunBody = secondRun.json() as {
        run: {
          id: string;
        };
      };
      await waitForCustomRun(secondRunBody.run.id);

      const secondTerminal = await customInject({
        method: 'GET',
        url: `/api/runs/${secondRunBody.run.id}/terminal`
      });
      expect(secondTerminal.statusCode).toBe(200);
      const secondTerminalBody = secondTerminal.json() as {
        terminal: {
          workspacePath: string | null;
        } | null;
      };
      expect(secondTerminalBody.terminal?.workspacePath).toBe(realRepoRoot);
    } finally {
      await customApp.close();
    }
  }, 15_000);

