  it('extends project intake generation time across artifact retries so automatic remediation can finish', async () => {
    const localRoot = fs.mkdtempSync(path.join(os.tmpdir(), 'ops-gateway-intake-retry-'));
    const scriptPath = path.join(localRoot, 'project-intake-retry-runner.mjs');
    const counterPath = path.join(localRoot, 'attempt-counter.txt');
    fs.mkdirSync(path.join(localRoot, 'skills'), { recursive: true });
    fs.writeFileSync(
      scriptPath,
      [
        "import fs from 'node:fs';",
        'const prompt = await new Promise((resolve) => {',
        "  let data = '';",
        "  process.stdin.setEncoding('utf8');",
        "  process.stdin.on('data', (chunk) => { data += chunk; });",
        "  process.stdin.on('end', () => resolve(data));",
        '});',
        `const counterPath = ${JSON.stringify(counterPath)};`,
        "const current = Number(fs.existsSync(counterPath) ? fs.readFileSync(counterPath, 'utf8') : '0') || 0;",
        'const attempt = current + 1;',
        "fs.writeFileSync(counterPath, String(attempt));",
        "const planMatch = prompt.match(/Update PLAN at: (.+)/);",
        "const prdMatch = prompt.match(/Update PRD at: (.+)/);",
        'await new Promise((resolve) => setTimeout(resolve, 1000));',
        'if (attempt >= 2 && planMatch && prdMatch) {',
        '  const planPath = planMatch[1].trim();',
        '  const prdPath = prdMatch[1].trim();',
        "  fs.writeFileSync(prdPath, '# Retry PRD\\n');",
        "  fs.writeFileSync(planPath, ['# Retry Plan', '', '```json', JSON.stringify([{ id: 'T-950', category: 'feature', description: 'Ship the contact page.', depends_on: [], steps: ['Create route'], criteria: ['Example: page renders', 'Negative: unknown route still 404s'], passes: false }], null, 2), '```', ''].join('\\n'));",
        '}',
        "process.stdout.write(`attempt ${attempt}`);"
      ].join('\n')
    );

    const localConfig = structuredClone(config) as any;
    localConfig.runtime.workspaceRoot = localRoot;
    localConfig.persistence.sqlitePath = path.join(localRoot, 'state.db');
    localConfig.skills.directories = [path.join(localRoot, 'skills')];
    localConfig.runtime.adapters.codex = {
      command: 'node',
      args: [scriptPath]
    };

    const localApp = await buildGatewayApp(localConfig as never, {
      skillRegistryRunner: skillInstallRunner
    });
    const localInject = async (options: Parameters<typeof localApp.inject>[0]) => {
      if (typeof options === 'string') {
        return localApp.inject(options);
      }
      const headers = { ...(options.headers ?? {}) } as Record<string, string>;
      const hasAuth = Boolean(headers.Authorization || headers.authorization || headers['x-api-token']);
      if (String(options.url ?? '').startsWith('/api/') && !hasAuth) {
        headers.Authorization = `Bearer ${localConfig.server.apiToken}`;
      }
      if (String(options.url ?? '').startsWith('/api/') && !headers['x-ops-role']) {
        headers['x-ops-role'] = 'operator';
      }
      return localApp.inject({
        ...options,
        headers
      });
    };

    try {
      const bootstrapBaseline = await localInject({
        method: 'POST',
        url: '/api/onboarding/ceo-baseline',
        payload: {
          actor: 'project-intake-retry-test'
        }
      });
      expect(bootstrapBaseline.statusCode).toBe(200);

      const updateEngineer = await localInject({
        method: 'PATCH',
        url: '/api/agents/profiles/software-engineer',
        payload: {
          executionMode: 'on_demand',
          defaultRuntime: 'codex',
          allowedRuntimes: ['codex', 'process', 'claude', 'gemini']
        }
      });
      expect(updateEngineer.statusCode).toBe(200);

      const limitsResponse = await localInject({
        method: 'GET',
        url: '/api/llm/limits'
      });
      expect(limitsResponse.statusCode).toBe(200);
      const limitsBody = limitsResponse.json() as { limits: Record<string, any> };
      const nextLimits = structuredClone(limitsBody.limits) as Record<string, any>;
      nextLimits.localHarnessByRuntime.codex = true;
      nextLimits.orchestratorLocalHarnessByRuntime.codex = true;
      const saveLimits = await localInject({
        method: 'PUT',
        url: '/api/llm/limits',
        payload: {
          actor: 'project-intake-retry-test',
          limits: nextLimits
        }
      });
      expect(saveLimits.statusCode).toBe(200);

      const repoRoot = path.join(localRoot, 'retry-repo');
      const planPath = path.join(repoRoot, '.agents', 'PLAN.md');
      const prdPath = path.join(repoRoot, '.agents', 'PRD.md');
      fs.mkdirSync(path.dirname(planPath), { recursive: true });
      fs.writeFileSync(planPath, '# Placeholder Plan\n');
      fs.writeFileSync(prdPath, '# Placeholder PRD\n');

      const intakeResponse = await localInject({
        method: 'POST',
        url: '/api/backlog/project-intake',
        payload: {
          mode: 'generate_and_sync',
          waitForGeneration: true,
          generationTimeoutMs: 5_000,
          prompt: 'Clone ugothere.ai and add a contact page.',
          planPath,
          prdPath,
          repoRoot,
          actor: 'project-intake-retry-test'
        }
      });

      expect(intakeResponse.statusCode).toBe(200);
      const intakeBody = intakeResponse.json() as {
        pipeline: {
          generationRunId: string | null;
          generationStatus: string | null;
          generationTimedOut: boolean;
        };
        sync: {
          parsedTasks: number;
          created: number;
          updated: number;
          mapped: Array<{ taskId: string; itemId: string }>;
        };
      };
      expect(typeof intakeBody.pipeline.generationRunId).toBe('string');
      expect(intakeBody.sync.parsedTasks).toBe(1);
      expect(intakeBody.sync.created + intakeBody.sync.updated).toBeGreaterThanOrEqual(1);
      expect(intakeBody.sync.mapped.some((entry) => entry.taskId === 'T-950')).toBe(true);
      expect(fs.readFileSync(counterPath, 'utf8').trim()).toBe('2');
    } finally {
      await localApp.close();
    }
  }, 25_000);

