  it('accepts company and CEO identity fields during onboarding and derives the CEO profile id', async () => {
    const customSystemPrompt = 'You are the CEO for Acme Labs. Keep answers concise and execution-first.';
    const applyBaseline = await inject({
      method: 'POST',
      url: '/api/onboarding/ceo-baseline',
      headers: {
        Authorization: `Bearer ${config.server.apiToken}`
      },
      payload: {
        actor: 'test',
        companyName: 'Acme Labs',
        ceoName: 'Acme Labs Command',
        ceoTitle: 'Chief Orchestrator',
        ceoSystemPrompt: customSystemPrompt
      }
    });
    expect(applyBaseline.statusCode).toBe(200);
    const applyBody = applyBaseline.json() as {
      companyName: string;
      ceoAgentId: string;
      onboarding: {
        companyName: string;
        ceoAgentId: string;
        ceoName?: string | null;
        ceoTitle?: string | null;
        ceoSystemPrompt?: string | null;
      };
      agent: {
        id: string;
        name: string;
        title: string;
        systemPrompt: string;
      };
    };
    expect(applyBody.companyName).toBe('Acme Labs');
    expect(applyBody.ceoAgentId).toBe('ceo-acme-labs');
    expect(applyBody.onboarding.companyName).toBe('Acme Labs');
    expect(applyBody.onboarding.ceoAgentId).toBe('ceo-acme-labs');
    expect(applyBody.onboarding.ceoName).toBe('Acme Labs Command');
    expect(applyBody.onboarding.ceoTitle).toBe('Chief Orchestrator');
    expect(applyBody.onboarding.ceoSystemPrompt).toBe(customSystemPrompt);
    expect(applyBody.agent.id).toBe('ceo-acme-labs');
    expect(applyBody.agent.name).toBe('Acme Labs Command');
    expect(applyBody.agent.title).toBe('Chief Orchestrator');
    expect(applyBody.agent.systemPrompt).toBe(customSystemPrompt);

    const listProfiles = await inject({
      method: 'GET',
      url: '/api/agents/profiles?includeDisabled=true'
    });
    expect(listProfiles.statusCode).toBe(200);
    const profilesBody = listProfiles.json() as {
      agents: Array<{ id: string; enabled: boolean; protectedDefault: boolean }>;
    };
    const fallbackCeo = profilesBody.agents.find((agent) => agent.id === 'ceo-default');
    const primaryCeo = profilesBody.agents.find((agent) => agent.id === 'ceo-acme-labs');
    expect(fallbackCeo).toBeUndefined();
    expect(primaryCeo?.enabled).toBe(true);
    expect(primaryCeo?.protectedDefault).toBe(true);
  });

